<?php

if ( ! defined( 'ABSPATH' ) ) {
    exit;
}

/**
 * Admin-facing dashboard scaffolding.
 * Developer: build admin menus + pages here to match Figma/admin designs.
 */
class N88_RFQ_Admin {

    public function __construct() {
        add_action( 'admin_menu', array( $this, 'register_menus' ) );
        add_action( 'admin_menu', array( $this, 'modify_board_menu_url' ), 999 ); // Run after menus are registered
        add_action( 'wp_ajax_n88_get_board_items_status', array( $this, 'ajax_get_board_items_status' ) );
        add_action( 'admin_enqueue_scripts', array( $this, 'dequeue_wp_auth_check_on_board' ), 999 );
    }

    /**
     * Lightweight slow-request instrumentation for board/admin AJAX endpoints.
     *
     * @param string $endpoint Endpoint label.
     * @param float  $started_at microtime(true) request start.
     * @param array  $context Optional debug context.
     * @return void
     */
    private function log_ajax_performance( $endpoint, $started_at, $context = array() ) {
        $duration_ms = ( microtime( true ) - (float) $started_at ) * 1000;
        $threshold   = 350;

        if ( $duration_ms < $threshold ) {
            return;
        }

        $payload = array_merge(
            array(
                'endpoint'    => (string) $endpoint,
                'duration_ms' => round( $duration_ms, 2 ),
            ),
            is_array( $context ) ? $context : array()
        );

        error_log( 'N88 AJAX performance: ' . wp_json_encode( $payload ) );
    }

    /**
     * Commit 3.C.17: Resolve grouped proposal context for a board item.
     *
     * A grouped proposal exists when a submitted/awarded bid carries a
     * `proposal_group_id` in bid meta_json. When revision tracking exists, only
     * current-revision bids are treated as active grouped proposals; awarded bids
     * remain eligible so downstream routing stays stable after award.
     *
     * @param int        $item_id              Item ID.
     * @param int|string $rfq_revision_current Current RFQ revision, when available.
     * @return array
     */
    private function get_item_batch_proposal_context( $item_id, $rfq_revision_current = null ) {
        global $wpdb;

        $item_id = absint( $item_id );
        if ( ! $item_id ) {
            return array(
                'has_batch_proposals'             => false,
                'batch_proposal_bid_count'        => 0,
                'batch_proposal_group_ids'        => array(),
                'batch_primary_proposal_group_id' => 0,
            );
        }

        $item_bids_table     = $wpdb->prefix . 'n88_item_bids';
        $bids_columns        = $wpdb->get_col( "DESCRIBE {$item_bids_table}" );
        $has_meta_json       = is_array( $bids_columns ) && in_array( 'meta_json', $bids_columns, true );
        $has_revision_column = is_array( $bids_columns ) && in_array( 'rfq_revision_at_submit', $bids_columns, true );

        $select_fields = 'bid_id, status';
        if ( $has_meta_json ) {
            $select_fields .= ', meta_json';
        }
        if ( $has_revision_column ) {
            $select_fields .= ', rfq_revision_at_submit';
        }

        $rows = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT {$select_fields}
                FROM {$item_bids_table}
                WHERE item_id = %d
                AND status IN ('submitted', 'awarded')
                ORDER BY bid_id DESC",
                $item_id
            ),
            ARRAY_A
        );

        $group_ids      = array();
        $grouped_bid_count = 0;
        $primary_group  = 0;
        $primary_bid_id = 0;

        foreach ( (array) $rows as $row ) {
            if ( ! $has_meta_json || empty( $row['meta_json'] ) ) {
                continue;
            }

            $bid_meta = json_decode( $row['meta_json'], true );
            if ( ! is_array( $bid_meta ) || empty( $bid_meta['proposal_group_id'] ) ) {
                continue;
            }

            $proposal_group_id = absint( $bid_meta['proposal_group_id'] );
            if ( ! $proposal_group_id ) {
                continue;
            }

            if ( $has_revision_column && null !== $rfq_revision_current && '' !== $rfq_revision_current ) {
                $bid_status    = isset( $row['status'] ) ? sanitize_text_field( $row['status'] ) : '';
                $bid_revision  = isset( $row['rfq_revision_at_submit'] ) && '' !== $row['rfq_revision_at_submit'] ? (string) $row['rfq_revision_at_submit'] : null;
                $revision_pass = ( 'awarded' === $bid_status ) || ( null !== $bid_revision && (string) $bid_revision === (string) $rfq_revision_current );

                if ( ! $revision_pass ) {
                    continue;
                }
            }

            $group_ids[ $proposal_group_id ] = $proposal_group_id;
            $grouped_bid_count++;
            if ( (int) $row['bid_id'] > $primary_bid_id ) {
                $primary_bid_id = (int) $row['bid_id'];
                $primary_group  = $proposal_group_id;
            }
        }

        $group_ids = array_values( array_unique( array_map( 'absint', $group_ids ) ) );
        sort( $group_ids );

        return array(
            'has_batch_proposals'             => ! empty( $group_ids ),
            'batch_proposal_bid_count'        => $grouped_bid_count,
            'batch_proposal_group_ids'        => $group_ids,
            'batch_primary_proposal_group_id' => $primary_group,
        );
    }

    private function get_item_validation_attachment_entries( $ids ) {
        $entries = array();
        foreach ( array_values( array_unique( array_map( 'absint', (array) $ids ) ) ) as $attachment_id ) {
            if ( ! $attachment_id ) {
                continue;
            }

            $url = wp_get_attachment_url( $attachment_id );
            if ( ! $url ) {
                continue;
            }

            $attached_file = get_attached_file( $attachment_id );
            $file_name     = '';
            if ( $attached_file ) {
                $file_name = wp_basename( $attached_file );
            }
            if ( ! $file_name ) {
                $file_name = wp_basename( wp_parse_url( $url, PHP_URL_PATH ) );
            }
            if ( $file_name ) {
                $file_name = sanitize_file_name( rawurldecode( html_entity_decode( $file_name, ENT_QUOTES, 'UTF-8' ) ) );
            }

            $entries[] = array(
                'id'    => $attachment_id,
                'url'   => esc_url_raw( $url ),
                'title' => $file_name ? $file_name : get_the_title( $attachment_id ),
            );
        }

        return $entries;
    }

    private function get_validation_supplier_company_address( $supplier_id ) {
        global $wpdb;

        $supplier_id = absint( $supplier_id );
        if ( ! $supplier_id ) {
            return 'Address pending from supplier.';
        }

        $profiles_table = $wpdb->prefix . 'supplier_company_profiles';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$profiles_table}'" ) !== $profiles_table ) {
            return 'Address pending from supplier.';
        }

        $profile = $wpdb->get_row(
            $wpdb->prepare(
                "SELECT company_name, address_line1, city, state, postal_code, country FROM {$profiles_table} WHERE supplier_id = %d LIMIT 1",
                $supplier_id
            ),
            ARRAY_A
        );

        if ( ! $profile ) {
            return 'Address pending from supplier.';
        }

        $parts = array();
        foreach ( array( 'company_name', 'address_line1', 'city', 'state', 'postal_code', 'country' ) as $key ) {
            if ( ! empty( $profile[ $key ] ) ) {
                $parts[] = sanitize_text_field( $profile[ $key ] );
            }
        }

        return ! empty( $parts ) ? implode( ', ', $parts ) : 'Address pending from supplier.';
    }

