    private function normalize_structured_address( $address, $fallback_name = '' ) {
        $normalized = array(
            'name'         => '',
            'address_line' => '',
            'city'         => '',
            'state'        => '',
            'country'      => '',
            'postal_code'  => '',
        );

        if ( is_array( $address ) ) {
            $normalized['name']         = isset( $address['name'] ) ? sanitize_text_field( $address['name'] ) : '';
            $normalized['address_line'] = isset( $address['address_line'] ) ? sanitize_text_field( $address['address_line'] ) : ( isset( $address['address_line1'] ) ? sanitize_text_field( $address['address_line1'] ) : '' );
            $normalized['city']         = isset( $address['city'] ) ? sanitize_text_field( $address['city'] ) : '';
            $normalized['state']        = isset( $address['state'] ) ? strtoupper( sanitize_text_field( $address['state'] ) ) : '';
            $normalized['country']      = isset( $address['country'] ) ? sanitize_text_field( $address['country'] ) : '';
            $normalized['postal_code']  = isset( $address['postal_code'] ) ? sanitize_text_field( $address['postal_code'] ) : ( isset( $address['zip_code'] ) ? sanitize_text_field( $address['zip_code'] ) : '' );
        } elseif ( is_string( $address ) && '' !== trim( $address ) ) {
            $normalized['address_line'] = sanitize_textarea_field( $address );
        }

        if ( ! $normalized['name'] && $fallback_name ) {
            $normalized['name'] = sanitize_text_field( $fallback_name );
        }

        return $normalized;
    }

    private function format_structured_address( $address, $multiline = false ) {
        $address = $this->normalize_structured_address( $address );
        $lines   = array();

        if ( ! empty( $address['name'] ) ) {
            $lines[] = $address['name'];
        }
        if ( ! empty( $address['address_line'] ) ) {
            $lines[] = $address['address_line'];
        }

        $locality = array_filter(
            array(
                $address['city'],
                $address['state'],
                $address['postal_code'],
            )
        );
        if ( ! empty( $locality ) ) {
            $lines[] = implode( ', ', $locality );
        }
        if ( ! empty( $address['country'] ) ) {
            $lines[] = $address['country'];
        }

        return implode( $multiline ? "\n" : ', ', $lines );
    }

    private function get_item_validation_card_status( $item_meta ) {
        $validation = isset( $item_meta['material_validation'] ) && is_array( $item_meta['material_validation'] )
            ? $item_meta['material_validation']
            : array();
        $request    = isset( $validation['request'] ) && is_array( $validation['request'] ) ? $validation['request'] : array();
        $supplier   = isset( $validation['supplier'] ) && is_array( $validation['supplier'] ) ? $validation['supplier'] : array();
        $review     = isset( $validation['review'] ) && is_array( $validation['review'] ) ? $validation['review'] : array();
        $commitment = isset( $validation['commitment'] ) && is_array( $validation['commitment'] ) ? $validation['commitment'] : array();

        $sample_status = isset( $validation['sample_status'] ) ? sanitize_key( $validation['sample_status'] ) : '';
        $supplier_status = isset( $supplier['status'] ) ? sanitize_key( $supplier['status'] ) : '';
        if ( ( ! $sample_status || 'sample_requested' === $sample_status ) && $supplier_status ) {
            $sample_status = $supplier_status;
        }
        if ( ! $sample_status ) {
            if ( ! empty( $review['approved_at'] ) ) {
                $sample_status = 'samples_approved';
            } elseif ( ! empty( $review['samples_received_at'] ) ) {
                $sample_status = 'samples_received';
            } elseif ( ! empty( $supplier_status ) ) {
                $sample_status = $supplier_status;
            } elseif ( ! empty( $request['requested_at'] ) ) {
                $sample_status = 'sample_requested';
            }
        }

        $payment_status = isset( $request['payment_status'] ) ? sanitize_key( $request['payment_status'] ) : '';
        $payment_mode   = isset( $request['payment_mode'] ) ? sanitize_key( $request['payment_mode'] ) : '';
        $sample_format  = isset( $request['sample_format'] ) ? sanitize_text_field( $request['sample_format'] ) : '';
        $supplier_id    = isset( $validation['supplier_id'] ) ? absint( $validation['supplier_id'] ) : ( isset( $request['supplier_id'] ) ? absint( $request['supplier_id'] ) : 0 );
        $is_physical_sample_request = 'physical' === strtolower( trim( $sample_format ) );
        $fabric_supplied_flag = isset( $item_meta['rfq_fabric_supplied_flag'] ) ? $item_meta['rfq_fabric_supplied_flag'] : '';
        $com_applicable       = in_array( strtolower( (string) $fabric_supplied_flag ), array( 'yes', '1', 'true' ), true );

        $request_shipping_address = $this->normalize_structured_address(
            isset( $request['shipping_address_fields'] ) ? $request['shipping_address_fields'] : ( isset( $request['shipping_address'] ) ? $request['shipping_address'] : array() )
        );
        $request_shipping_address_text = $this->format_structured_address( $request_shipping_address, true );

        $commitment_address = $this->normalize_structured_address(
            isset( $commitment['com_delivery_address_fields'] ) ? $commitment['com_delivery_address_fields'] : ( isset( $commitment['com_delivery_address'] ) ? $commitment['com_delivery_address'] : array() )
        );
        if ( ! $this->format_structured_address( $commitment_address ) && $supplier_id ) {
            $commitment_address = $this->normalize_structured_address(
                array(
                    'address_line' => $this->get_validation_supplier_company_address( $supplier_id ),
                )
            );
        }
        $commitment['com_delivery_address'] = $this->format_structured_address( $commitment_address );

        $supplier_files    = $this->get_item_validation_attachment_entries( isset( $supplier['sample_file_ids'] ) ? $supplier['sample_file_ids'] : array() );
        $po_uploaded       = ! empty( $commitment['po_file_id'] );
        $samples_approved  = ! empty( $review['approved_at'] );
        $has_awarded_bid   = false;
        if ( isset( $item_meta['item_status'] ) && 'Awarded' === $item_meta['item_status'] ) {
            $has_awarded_bid = true;
        } elseif ( ! empty( $item_meta['awarded_bid_snapshot'] ) ) {
            $has_awarded_bid = true;
        }
        $com_status        = isset( $commitment['com_status'] ) ? sanitize_key( $commitment['com_status'] ) : '';
        $com_in_transit    = in_array( $com_status, array( 'com_in_transit', 'shipped', 'in_transit' ), true );
        $com_completed     = ! $com_applicable || in_array( $com_status, array( 'com_delivered', 'received', 'confirmed' ), true );
        $deposit_status    = isset( $commitment['deposit_status'] ) ? sanitize_key( $commitment['deposit_status'] ) : '';
        $deposit_confirmed = in_array( $deposit_status, array( 'confirmed', 'paid', 'recorded' ), true );
        $readiness         = array(
            'validation_complete' => $samples_approved,
            'awaiting_po'         => $has_awarded_bid && $samples_approved && ! $po_uploaded,
            'awaiting_deposit'    => $has_awarded_bid && $samples_approved && $po_uploaded && ! $deposit_confirmed,
            'awaiting_com'        => $has_awarded_bid && $samples_approved && $po_uploaded && $deposit_confirmed && $com_applicable && ! $com_completed,
        );
        $can_commit        = $has_awarded_bid && $samples_approved && $po_uploaded && $deposit_confirmed && $com_completed;

        $card_status_text  = '';
        $card_status_color = '#f4b400';

        if ( $can_commit ) {
            $card_status_text  = 'Ready for Production';
            $card_status_color = '#2e7d32';
        } elseif ( $readiness['awaiting_deposit'] ) {
            $card_status_text  = 'Awaiting Deposit';
            $card_status_color = '#2e7d32';
        } elseif ( $com_in_transit ) {
            $card_status_text  = 'COM Shipped';
            $card_status_color = '#2e7d32';
        } elseif ( $readiness['awaiting_com'] ) {
            $card_status_text  = 'Awaiting COM';
            $card_status_color = '#2e7d32';
        } elseif ( $readiness['awaiting_po'] ) {
            $card_status_text  = 'Awaiting PO';
            $card_status_color = '#2e7d32';
        } elseif ( 'samples_approved' === $sample_status ) {
            $card_status_text  = $has_awarded_bid ? 'Awaiting PO' : 'Samples Approved';
            $card_status_color = $has_awarded_bid ? '#2e7d32' : '#f4b400';
        } elseif ( 'samples_received' === $sample_status ) {
            $card_status_text  = 'Sample Received';
            $card_status_color = '#f4b400';
        } elseif ( in_array( $sample_status, array( 'delivered', 'shipped', 'in_transit' ), true ) ) {
            $card_status_text  = 'Samples Shipped';
            $card_status_color = '#f4b400';
        } elseif ( 'under_review' === $sample_status ) {
            $card_status_text  = 'Review Samples';
            $card_status_color = '#f4b400';
        } elseif ( 'in_preparation' === $sample_status ) {
            $card_status_text  = 'Samples In Preparation';
            $card_status_color = '#f4b400';
        } elseif ( 'sample_requested' === $sample_status ) {
            $card_status_text  = 'Sample Requested';
            $card_status_color = '#f4b400';
        }

        return array(
            'enabled'                 => ! empty( $request['requested_at'] ) || ! empty( $review['approved_at'] ) || ! empty( $supplier['updated_at'] ) || ! empty( $commitment['po_uploaded_at'] ),
            'supplier_id'             => $supplier_id,
            'supplier_name'           => isset( $validation['supplier_name'] ) ? sanitize_text_field( $validation['supplier_name'] ) : '',
            'bid_id'                  => isset( $validation['bid_id'] ) ? absint( $validation['bid_id'] ) : 0,
            'wireframe_supplier'      => ! empty( $validation['wireframe_supplier'] ),
            'sample_status'           => $sample_status,
            'payment_mode'            => $payment_mode,
            'payment_status'          => $payment_status,
            'request'                 => array(
                'sample_types'         => isset( $request['sample_types'] ) && is_array( $request['sample_types'] ) ? array_values( array_map( 'sanitize_text_field', $request['sample_types'] ) ) : array(),
                'sample_format'        => isset( $request['sample_format'] ) ? sanitize_text_field( $request['sample_format'] ) : '',
                'instructions'         => isset( $request['instructions'] ) ? sanitize_textarea_field( $request['instructions'] ) : '',
                'shipping_address'     => $request_shipping_address_text,
                'shipping_address_fields' => $request_shipping_address,
                'reference_files'      => $this->get_item_validation_attachment_entries( isset( $request['reference_file_ids'] ) ? $request['reference_file_ids'] : array() ),
                'requested_at'         => isset( $request['requested_at'] ) ? $request['requested_at'] : null,
                'payment_submitted_at' => isset( $request['payment_submitted_at'] ) ? $request['payment_submitted_at'] : null,
                'payment_proof_files'  => $this->get_item_validation_attachment_entries( isset( $request['payment_proof_file_ids'] ) ? $request['payment_proof_file_ids'] : array() ),
            ),
            'supplier'                => array(
                'status'               => isset( $supplier['status'] ) ? sanitize_key( $supplier['status'] ) : '',
                'tracking_number'      => isset( $supplier['tracking_number'] ) ? sanitize_text_field( $supplier['tracking_number'] ) : '',
                'note'                 => isset( $supplier['note'] ) ? sanitize_textarea_field( $supplier['note'] ) : '',
                'files'                => $supplier_files,
                'updated_at'           => isset( $supplier['updated_at'] ) ? $supplier['updated_at'] : null,
                'submitted_by'         => isset( $supplier['submitted_by'] ) ? absint( $supplier['submitted_by'] ) : 0,
            ),
            'review'                  => array(
                'samples_received_at'      => isset( $review['samples_received_at'] ) ? $review['samples_received_at'] : null,
                'approved_material_codes'  => isset( $review['approved_material_codes'] ) && is_array( $review['approved_material_codes'] ) ? array_values( array_map( 'sanitize_text_field', $review['approved_material_codes'] ) ) : array(),
                'approved_finish_codes'    => isset( $review['approved_finish_codes'] ) && is_array( $review['approved_finish_codes'] ) ? array_values( array_map( 'sanitize_text_field', $review['approved_finish_codes'] ) ) : array(),
                'approved_sample_images'   => $this->get_item_validation_attachment_entries( isset( $review['approved_sample_image_ids'] ) ? $review['approved_sample_image_ids'] : array() ),
                'selected_supplier_samples' => array_map( 'absint', isset( $review['selected_supplier_sample_ids'] ) ? (array) $review['selected_supplier_sample_ids'] : array() ),
                'notes'                    => isset( $review['notes'] ) ? sanitize_textarea_field( $review['notes'] ) : '',
                'approved_at'              => isset( $review['approved_at'] ) ? $review['approved_at'] : null,
            ),
            'commitment'              => array(
                'po_file'               => ! empty( $commitment['po_file_id'] ) ? array(
                    'id'  => absint( $commitment['po_file_id'] ),
                    'url' => esc_url_raw( wp_get_attachment_url( absint( $commitment['po_file_id'] ) ) ),
                ) : null,
                'po_uploaded_at'        => isset( $commitment['po_uploaded_at'] ) ? $commitment['po_uploaded_at'] : null,
                'com_applicable'        => $com_applicable,
                'com_required'          => ! empty( $commitment['com_required'] ) || $com_applicable,
                'com_qty'               => isset( $commitment['com_qty'] ) ? sanitize_text_field( $commitment['com_qty'] ) : '',
                'com_delivery_address'  => $this->format_structured_address( $commitment_address, true ),
                'com_delivery_address_fields' => $commitment_address,
                'com_tracking_number'   => isset( $commitment['com_tracking_number'] ) ? sanitize_text_field( $commitment['com_tracking_number'] ) : '',
                'com_status'            => $com_status,
                'com_shipped_at'        => isset( $commitment['com_shipped_at'] ) ? $commitment['com_shipped_at'] : null,
                'com_delivered_at'      => isset( $commitment['com_delivered_at'] ) ? $commitment['com_delivered_at'] : null,
                'deposit_supplier_name' => isset( $commitment['deposit_supplier_name'] ) ? sanitize_text_field( $commitment['deposit_supplier_name'] ) : '',
                'deposit_amount'        => isset( $commitment['deposit_amount'] ) ? floatval( $commitment['deposit_amount'] ) : null,
                'deposit_status'        => $deposit_status,
                'deposit_receipt_files' => $this->get_item_validation_attachment_entries( isset( $commitment['deposit_receipt_file_ids'] ) ? $commitment['deposit_receipt_file_ids'] : array() ),
                'deposit_confirmed_at'  => isset( $commitment['deposit_confirmed_at'] ) ? $commitment['deposit_confirmed_at'] : null,
            ),
            'readiness_flags'         => $readiness,
            'can_commit'              => $can_commit,
            'approved_material_codes' => isset( $item_meta['approved_material_codes'] ) && is_array( $item_meta['approved_material_codes'] ) ? array_values( $item_meta['approved_material_codes'] ) : array(),
            'approved_finish_codes'   => isset( $item_meta['approved_finish_codes'] ) && is_array( $item_meta['approved_finish_codes'] ) ? array_values( $item_meta['approved_finish_codes'] ) : array(),
            'approved_sample_images'  => $this->get_item_validation_attachment_entries( isset( $item_meta['approved_sample_images'] ) ? $item_meta['approved_sample_images'] : array() ),
            'validation_notes'        => isset( $item_meta['validation_notes'] ) ? sanitize_textarea_field( $item_meta['validation_notes'] ) : '',
            'card_status_text'        => $card_status_text,
            'card_status_color'       => $card_status_color,
        );
    }

    /**
     * Map unified message context keys to workflow step indexes.
     *
     * @param string $context_type Context key.
     * @return int|null
     */
    private function get_item_message_context_step_index( $context_type ) {
        $normalized = sanitize_key( (string) $context_type );
        $map        = array(
            'step_1_responses'  => 0,
            'step_2_validation' => 1,
            'step_3_commitment' => 2,
            'step_4_production' => 3,
            'step_5_quality'    => 4,
            'step_6_delivery'   => 5,
        );

        return isset( $map[ $normalized ] ) ? $map[ $normalized ] : null;
    }

    /**
     * Dequeue wp-auth-check on the Board page to avoid "Cannot read properties of undefined (reading 'hasClass')".
     * WordPress auth-check expects #wp-auth-check-wrap; when admin bar is hidden/removed the reference can be undefined.
     */
    public function dequeue_wp_auth_check_on_board() {
        $page = isset( $_GET['page'] ) ? sanitize_text_field( wp_unslash( $_GET['page'] ) ) : '';
        if ( $page === 'n88-rfq-board-demo' ) {
            wp_dequeue_script( 'wp-auth-check' );
        }
    }

    public function render_notifications_center() {
        if ( ! $this->check_plugin_access() ) {
            wp_die( __( 'You do not have permission to view this page.', 'n88-rfq' ) );
        }

        global $wpdb;
        $table_notifications = $wpdb->prefix . 'project_notifications';
        $table_projects      = $wpdb->prefix . 'projects';
        $table_users         = $wpdb->users;

        $status = isset( $_GET['status'] ) ? sanitize_text_field( $_GET['status'] ) : 'all';
        $type   = isset( $_GET['notification_type'] ) ? sanitize_text_field( $_GET['notification_type'] ) : '';
        $limit  = isset( $_GET['limit'] ) ? max( 10, min( 500, intval( $_GET['limit'] ) ) ) : 100;

        $admin_users = get_users( array( 'role' => 'administrator', 'fields' => 'ID' ) );
        $admin_ids = array_map( 'intval', $admin_users );

        $where = array( '1=1' );
        if ( 'unread' === $status ) {
            $where[] = 'n.is_read = 0';
        } elseif ( 'read' === $status ) {
            $where[] = 'n.is_read = 1';
        }

        $prepare_values = array();

        if ( ! empty( $admin_ids ) ) {
            $placeholders = implode( ',', array_fill( 0, count( $admin_ids ), '%d' ) );
            $where[] = "n.user_id IN ( {$placeholders} )";
            $prepare_values = array_merge( $prepare_values, $admin_ids );
        }

        if ( ! empty( $type ) ) {
            $where[] = 'n.notification_type = %s';
            $prepare_values[] = $type;
        }

        $where_sql = implode( ' AND ', $where );

        $query = "
            SELECT n.*, p.project_name, p.user_id AS project_owner_id,
                recipient.display_name AS recipient_name,
                owner.display_name AS owner_name
            FROM {$table_notifications} n
            LEFT JOIN {$table_projects} p ON n.project_id = p.id
            LEFT JOIN {$table_users} recipient ON n.user_id = recipient.ID
            LEFT JOIN {$table_users} owner ON p.user_id = owner.ID
            WHERE {$where_sql}
            ORDER BY n.created_at DESC
            LIMIT %d
        ";

        $prepare_values[] = $limit;
        $notifications = $wpdb->get_results( $wpdb->prepare( $query, $prepare_values ) );

        // Table name is safe (from $wpdb->prefix), but we validate it contains only safe characters
        $table_notifications_safe = preg_replace( '/[^a-zA-Z0-9_]/', '', $table_notifications );
        $notification_types = $wpdb->get_col( "SELECT DISTINCT notification_type FROM {$table_notifications_safe} ORDER BY notification_type ASC" );
        ?>
        <div class="wrap n88-admin-notifications">
            <h1><?php esc_html_e( 'Notifications Center', 'n88-rfq' ); ?></h1>

            <form method="get" class="n88-filters">
                <input type="hidden" name="page" value="n88-rfq-notifications" />
                <label>
                    <span><?php esc_html_e( 'Status', 'n88-rfq' ); ?></span>
                    <select name="status">
                        <option value="all" <?php selected( $status, 'all' ); ?>><?php esc_html_e( 'All', 'n88-rfq' ); ?></option>
                        <option value="unread" <?php selected( $status, 'unread' ); ?>><?php esc_html_e( 'Unread', 'n88-rfq' ); ?></option>
                        <option value="read" <?php selected( $status, 'read' ); ?>><?php esc_html_e( 'Read', 'n88-rfq' ); ?></option>
                    </select>
                </label>

                <label>
                    <span><?php esc_html_e( 'Type', 'n88-rfq' ); ?></span>
                    <select name="notification_type">
                        <option value=""><?php esc_html_e( 'All Types', 'n88-rfq' ); ?></option>
                        <?php foreach ( $notification_types as $notif_type ) : ?>
                            <option value="<?php echo esc_attr( $notif_type ); ?>" <?php selected( $type, $notif_type ); ?>>
                                <?php echo esc_html( ucwords( str_replace( '_', ' ', $notif_type ) ) ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                </label>

                <label>
                    <span><?php esc_html_e( 'Limit', 'n88-rfq' ); ?></span>
                    <input type="number" name="limit" value="<?php echo esc_attr( $limit ); ?>" min="10" max="500" />
                </label>

                <button class="button button-primary"><?php esc_html_e( 'Filter', 'n88-rfq' ); ?></button>
            </form>

            <table class="widefat fixed striped n88-notifications-table">
                <thead>
                    <tr>
                        <th><?php esc_html_e( 'Date', 'n88-rfq' ); ?></th>
                        <th><?php esc_html_e( 'Project', 'n88-rfq' ); ?></th>
                        <th><?php esc_html_e( 'Recipient', 'n88-rfq' ); ?></th>
                        <th><?php esc_html_e( 'Type', 'n88-rfq' ); ?></th>
                        <th><?php esc_html_e( 'Message', 'n88-rfq' ); ?></th>
                        <th><?php esc_html_e( 'Status', 'n88-rfq' ); ?></th>
                    </tr>
                </thead>
                <tbody>
                    <?php if ( empty( $notifications ) ) : ?>
                        <tr>
                            <td colspan="6" style="text-align:center;"><?php esc_html_e( 'No notifications found for the selected filters.', 'n88-rfq' ); ?></td>
                        </tr>
                    <?php else : ?>
                        <?php foreach ( $notifications as $notification ) : ?>
                            <tr>
                                <td>
                                    <strong><?php echo esc_html( date_i18n( get_option( 'date_format' ), strtotime( $notification->created_at ) ) ); ?></strong>
                                    <div class="description"><?php echo esc_html( date_i18n( get_option( 'time_format' ), strtotime( $notification->created_at ) ) ); ?></div>
                                </td>
                                <td>
                                    <?php if ( $notification->project_id ) : ?>
                                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=n88-rfq-projects&project_id=' . $notification->project_id ) ); ?>">
                                            <?php echo esc_html( $notification->project_name ?: __( 'Unknown Project', 'n88-rfq' ) ); ?>
                                        </a>
                                        <?php if ( $notification->owner_name ) : ?>
                                            <div class="description"><?php printf( esc_html__( 'Owner: %s', 'n88-rfq' ), esc_html( $notification->owner_name ) ); ?></div>
                                        <?php endif; ?>
                                    <?php else : ?>
                                        <em><?php esc_html_e( 'General', 'n88-rfq' ); ?></em>
                                    <?php endif; ?>
                                </td>
                                <td>
                                    <?php echo esc_html( $notification->recipient_name ?: __( 'Unknown user', 'n88-rfq' ) ); ?>
                                    <div class="description"><?php printf( esc_html__( 'User ID: %d', 'n88-rfq' ), (int) $notification->user_id ); ?></div>
                                </td>
                                <td>
                                    <span class="n88-type-badge"><?php echo esc_html( ucwords( str_replace( '_', ' ', $notification->notification_type ) ) ); ?></span>
                                </td>
                                <td><?php echo esc_html( $notification->message ); ?></td>
                                <td>
                                    <?php if ( $notification->is_read ) : ?>
                                        <span class="status-read"><?php esc_html_e( 'Read', 'n88-rfq' ); ?></span>
                                    <?php else : ?>
                                        <span class="status-unread"><?php esc_html_e( 'Unread', 'n88-rfq' ); ?></span>
                                    <?php endif; ?>
                                </td>
                            </tr>
                        <?php endforeach; ?>
                    <?php endif; ?>
                </tbody>
            </table>
        </div>

        <style>
            .n88-admin-notifications .n88-filters {
                display: flex;
                gap: 20px;
                align-items: flex-end;
                margin-bottom: 20px;
                flex-wrap: wrap;
            }
            .n88-admin-notifications .n88-filters label {
                display: flex;
                flex-direction: column;
                font-weight: 600;
            }
            .n88-notifications-table .description {
                color: #666;
                font-size: 12px;
            }
            .n88-type-badge {
                display: inline-block;
                padding: 4px 10px;
                border-radius: 999px;
                background: #eef2ff;
                color: #3730a3;
                font-size: 12px;
                text-transform: uppercase;
                letter-spacing: 0.5px;
            }
            .status-read,
            .status-unread {
                display: inline-flex;
                align-items: center;
                gap: 6px;
                font-weight: 600;
            }
            .status-read::before,
            .status-unread::before {
                content: '';
                width: 8px;
                height: 8px;
                border-radius: 50%;
                display: inline-block;
            }
            .status-read {
                color: #2e7d32;
            }
            .status-read::before {
                background: #2e7d32;
            }
            .status-unread {
                color: #c62828;
            }
            .status-unread::before {
                background: #c62828;
            }
        </style>
        <?php
    }

