                            "SELECT id, name, description, display_order
                            FROM {$rooms_table}
                            WHERE project_id = %d AND deleted_at IS NULL
                            ORDER BY display_order ASC, created_at ASC",
                            $selected_project_id
                        ),
                        ARRAY_A
                    );
