                <?php endif; ?>
                <?php endif; ?>
            </div>
            
            <script>
            (function() {
                window.n88NormalizeMeasurementType = function(type) {
                    var val = String(type || '').trim().toLowerCase();
                    if (val === 'linear' || val === 'length' || val === 'linear-length') return 'linear_length';
                    if (val === 'quantity' || val === 'quantityonly') return 'quantity_only';
                    if (val === 'custom' || val === 'custom_spec') return 'custom_specification';
                    if (val === 'dimensions' || val === 'area' || val === 'linear_length' || val === 'quantity_only' || val === 'custom_specification') return val;
                    return '';
                };
                window.n88GetCategoryMeasurementType = function(category) {
                    var cat = String(category || '').trim().toUpperCase();
                    if (!cat) return 'dimensions';
                    if (
                        cat === 'ACOUSTIC PANELS' ||
                        cat === 'FLOORING' ||
                        cat === 'GRANITE' ||
                        cat === 'MARBLE / STONE' ||
                        cat === 'PORCELAIN / CERAMIC SLABS' ||
                        cat === 'QUARTZ' ||
                        cat === 'RUGS / CARPETS' ||
                        cat === 'STONE (MARBLE / GRANITE / QUARTZ)' ||
                        cat === 'TERRAZZO' ||
                        cat === 'TILE (WALL / FLOOR)' ||
                        cat === 'WALLCOVERINGS' ||
                        cat === 'WALLCOVERINGS / FINISHES' ||
                        cat === 'STONE (MARBLE / GRANITE / QUARTZ)' ||
                        cat === 'RUGS / CARPETS'
                    ) return 'area';
                    if (
                        cat === 'DRAPERY' ||
                        cat === 'DRAPERY / WINDOW TREATMENTS' ||
                        cat === 'WINDOW TREATMENTS / SHADES'
                    ) return 'linear_length';
                    if (
                        cat === 'APPLIANCES' ||
                        cat === 'BATHROOM FIXTURES' ||
                        cat === 'DECORATIVE ACCESSORIES' ||
                        cat === 'DECORATIVE LIGHTING' ||
                        cat === 'ELECTRICAL / LED COMPONENTS' ||
                        cat === 'FAUCETS / HARDWARE (PLUMBING)' ||
                        cat === 'GLASS / MIRRORS' ||
                        cat === 'LIGHTING' ||
                        cat === 'HARDWARE / ACCESSORIES' ||
                        cat === 'KITCHEN FIXTURES' ||
                        cat === 'MIRRORS' ||
                        cat === 'SINKS / BASINS' ||
                        cat === 'SHOWER SYSTEMS / ACCESSORIES'
                    ) return 'quantity_only';
                    return 'dimensions';
                };
                window.n88DesignerCategoryOptions = [
                    'Indoor Furniture',
                    'Indoor Furniture (Casegoods)',
                    'Outdoor Furniture',
                    'Pool Furniture',
                    'UPHOLSTERY',
                    'Acoustic Panels',
                    'Appliances',
                    'Architectural Lighting',
                    'Artwork',
                    'Bathroom Fixtures',
                    'Cabinetry / Millwork (Custom)',
                    'Casegoods (Beds Nightstands Desks Consoles)',
                    'Chairs & Armchairs (Indoor)',
                    'Custom Sourcing / Not Listed',
                    'Decorative Accessories',
                    'Decorative Lighting',
                    'Dining Tables (Indoor)',
                    'Drapery',
                    'Drapery / Window Treatments',
                    'Electrical / LED Components',
                    'Fabric Sample',
                    'Facade Materials',
                    'Faucets / Hardware (Plumbing)',
                    'Flooring',
                    'Glass / Mirrors',
                    'Granite',
                    'Hardware / Accessories',
                    'Kitchen Fixtures',
                    'Lighting',
                    'Marble / Stone',
                    'Material Sample Kit',
                    'Metalwork',
                    'Millwork / Cabinetry',
                    'Mirrors',
                    'Other',
                    'Outdoor Dining Sets',
                    'Outdoor Loungers & Daybeds',
                    'Outdoor Seating',
                    'Pergola / Shade Components',
                    'Planters',
                    'Porcelain / Ceramic Slabs',
                    'Quartz',
                    'Railings',
                    'Rugs / Carpets',
                    'Screens / Louvers',
                    'Sculptural Objects',
                    'Shower Systems / Accessories',
                    'Sinks / Basins',
                    'Sofas & Seating (Indoor)',
                    'Stone (Marble / Granite / Quartz)',
                    'Terrazzo',
                    'Tile (Wall / Floor)',
                    'Wallcoverings',
                    'Wallcoverings / Finishes',
                    'Window Treatments / Shades'
                ];
                window.n88CategoryKeywordCache = window.n88CategoryKeywordCache || {};
                window.n88CategoryKeywordPending = window.n88CategoryKeywordPending || {};
                window.n88LoadCategoryKeywords = function(categoryName) {
                    var normalizedCategory = String(categoryName || '').trim();
                    if (!normalizedCategory) return Promise.resolve([]);
                    if (window.n88CategoryKeywordCache.hasOwnProperty(normalizedCategory)) {
                        return Promise.resolve(window.n88CategoryKeywordCache[normalizedCategory]);
                    }
                    if (window.n88CategoryKeywordPending[normalizedCategory]) {
                        return window.n88CategoryKeywordPending[normalizedCategory];
                    }
                    var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '/wp-admin/admin-ajax.php';
                    var nonce = (window.n88BoardNonce && window.n88BoardNonce.nonce_get_keywords) || (window.n88BoardData && window.n88BoardData.nonce_get_keywords) || '';
                    if (!nonce) return Promise.resolve([]);
                    var formData = new FormData();
                    formData.append('action', 'n88_get_keywords_by_category');
                    formData.append('category_name', normalizedCategory);
                    formData.append('_ajax_nonce', nonce);
                    window.n88CategoryKeywordPending[normalizedCategory] = fetch(ajaxUrl, { method: 'POST', body: formData, credentials: 'same-origin' })
                        .then(function(response) { return response.json(); })
                        .then(function(data) {
                            var keywords = (data && data.success && data.data && Array.isArray(data.data.keywords)) ? data.data.keywords : [];
                            window.n88CategoryKeywordCache[normalizedCategory] = keywords;
                            delete window.n88CategoryKeywordPending[normalizedCategory];
                            return keywords;
                        })
                        .catch(function() {
                            window.n88CategoryKeywordCache[normalizedCategory] = [];
                            delete window.n88CategoryKeywordPending[normalizedCategory];
                            return [];
                        });
                    return window.n88CategoryKeywordPending[normalizedCategory];
                };
                window.n88GetEffectiveMeasurementType = function(rawType, category) {
                    return window.n88NormalizeMeasurementType(rawType) || window.n88GetCategoryMeasurementType(category);
                };
                window.n88ToPositiveNumber = function(value) {
                    var num = parseFloat(value);
                    return isNaN(num) || num <= 0 ? 0 : num;
                };
                window.n88GetMeasurementData = function(source) {
                    source = source || {};
                    var category = source.category || source.item_type || '';
                    var type = window.n88GetEffectiveMeasurementType(source.measurement_type, category);
                    return {
                        measurement_type: type,
                        category: category,
                        width: window.n88ToPositiveNumber(source.width),
                        depth: window.n88ToPositiveNumber(source.depth),
                        height: window.n88ToPositiveNumber(source.height),
                        dimension_unit: source.dimension_unit || source.unit || 'in',
                        measurement_area: window.n88ToPositiveNumber(source.measurement_area),
                        measurement_area_unit: source.measurement_area_unit || 'sq_ft',
                        measurement_length: window.n88ToPositiveNumber(source.measurement_length),
                        measurement_length_unit: source.measurement_length_unit || 'ft',
                        custom_specification: String(source.custom_specification || '').trim()
                    };
                };
                window.n88GetMeasurementMissingLabels = function(source) {
                    var data = window.n88GetMeasurementData(source);
                    if (data.measurement_type === 'area') {
                        return data.measurement_area > 0 ? [] : ['Area'];
                    }
                    if (data.measurement_type === 'linear_length') {
                        return data.measurement_length > 0 ? [] : ['Linear Length'];
                    }
                    if (data.measurement_type === 'custom_specification') {
                        return data.custom_specification ? [] : ['Specification Details'];
                    }
                    if (data.measurement_type === 'quantity_only') {
                        return [];
                    }
                    var missing = [];
                    if (data.width <= 0) missing.push('Width');
                    if (data.depth <= 0) missing.push('Depth');
                    if (data.height <= 0) missing.push('Height');
                    return missing;
                };
                window.n88FormatMeasurementSummary = function(source) {
                    var data = window.n88GetMeasurementData(source);
                    if (data.measurement_type === 'area') {
                        return data.measurement_area > 0 ? (data.measurement_area + ' ' + (data.measurement_area_unit === 'sq_m' ? 'sq m' : 'sq ft')) : null;
                    }
                    if (data.measurement_type === 'linear_length') {
                        return data.measurement_length > 0 ? (data.measurement_length + ' ' + data.measurement_length_unit) : null;
                    }
                    if (data.measurement_type === 'custom_specification') {
                        return data.custom_specification || null;
                    }
                    if (data.measurement_type === 'quantity_only') {
                        return 'Quantity only';
                    }
                    if (!data.width || !data.depth || !data.height) return null;
                    var unitStr = data.dimension_unit === 'in' ? '"' : data.dimension_unit;
                    return data.width + unitStr + 'W x ' + data.depth + unitStr + 'D x ' + data.height + unitStr + 'H';
                };
                // Fix 2: Add body class when project is selected (for top spacing)
                var urlParams = new URLSearchParams(window.location.search);
                var projectId = urlParams.get('project_id');
                if (projectId && projectId !== '0') {
                    document.body.classList.add('has-project-selected');
                }
                
                var trigger = document.getElementById('n88-profile-dropdown-trigger');
                var dropdown = document.getElementById('n88-profile-dropdown');
                
                if (trigger && dropdown) {
                    trigger.addEventListener('click', function(e) {
                        e.stopPropagation();
                        dropdown.style.display = dropdown.style.display === 'none' ? 'block' : 'none';
                    });
                    
                    // Close dropdown when clicking outside
                    document.addEventListener('click', function(e) {
                        if (!trigger.contains(e.target) && !dropdown.contains(e.target)) {
                            dropdown.style.display = 'none';
                        }
                    });
                }
                
                // Message System Operator: scroll to Concierge overlay in canvas
                var msgOpBtn = document.getElementById('n88-message-system-operator');
                if (msgOpBtn) {
                    msgOpBtn.addEventListener('click', function() {
                        var el = document.getElementById('n88-concierge-overlay');
                        var container = document.getElementById('n88-board-canvas-container');
                        if (el && container) {
                            el.scrollIntoView({ behavior: 'smooth', block: 'start' });
                        }
                    });
                }
                
                // Commit 2.5.2: Create Project / Add Room / Invite - open modal on click. Init when DOM ready.
                function initAddProjectAndRoomModals() {
                // Move modal backdrops to body so they appear above canvas (fix: modal behind canvas / white space)
                [ 'n88-add-project-modal-backdrop', 'n88-add-room-modal-backdrop', 'n88-invite-team-member-modal-backdrop' ].forEach(function(id) {
                    var el = document.getElementById(id);
                    if (el && el.parentNode && el.parentNode !== document.body) document.body.appendChild(el);
                });
                var createProjectBtn = document.getElementById('n88-create-project-btn');
                var addProjectBackdrop = document.getElementById('n88-add-project-modal-backdrop');
                var addProjectCloseBtn = document.getElementById('n88-add-project-modal-close');
                var addProjectSubmitBtn = document.getElementById('n88-modal-create-project-submit');
                var addProjectNameInput = document.getElementById('n88-modal-project-name');
                var addProjectResultEl = document.getElementById('n88-add-project-modal-result');
                
                function openAddProjectModal() {
                    if (addProjectBackdrop) {
                        addProjectBackdrop.classList.add('n88-modal-open');
                        addProjectBackdrop.setAttribute('aria-hidden', 'false');
                        document.body.classList.add('n88-modal-open');
                        if (addProjectNameInput) { addProjectNameInput.value = ''; addProjectNameInput.focus(); }
                        if (addProjectResultEl) { addProjectResultEl.textContent = ''; addProjectResultEl.className = 'n88-result'; }
                    }
                }
                function closeAddProjectModal() {
                    if (addProjectBackdrop) {
                        addProjectBackdrop.classList.remove('n88-modal-open');
                        addProjectBackdrop.setAttribute('aria-hidden', 'true');
                        document.body.classList.remove('n88-modal-open');
                    }
                }
                
                if (createProjectBtn) createProjectBtn.addEventListener('click', openAddProjectModal);
                if (addProjectCloseBtn) addProjectCloseBtn.addEventListener('click', closeAddProjectModal);
                if (addProjectBackdrop) addProjectBackdrop.addEventListener('click', function(e) { if (e.target === addProjectBackdrop) closeAddProjectModal(); });
                
                if (addProjectSubmitBtn && addProjectNameInput) {
                    addProjectSubmitBtn.addEventListener('click', function() {
                        var projectName = (addProjectNameInput.value || '').trim();
                        if (!projectName) {
                            if (addProjectResultEl) { addProjectResultEl.textContent = 'Please enter a project name.'; addProjectResultEl.className = 'n88-result error'; }
                            return;
                        }
                        
                        var nonce = (window.n88BoardNonce && window.n88BoardNonce.nonce) || (window.n88BoardData && window.n88BoardData.nonce) || '';
                        if (!nonce) {
                            if (addProjectResultEl) { addProjectResultEl.textContent = 'Security token missing. Please refresh the page and try again.'; addProjectResultEl.className = 'n88-result error'; }
                            return;
                        }
                        var urlParams = new URLSearchParams(window.location.search);
                        var boardId = urlParams.get('board_id') || 0;
                        if (!boardId || boardId === '0') {
                            if (addProjectResultEl) { addProjectResultEl.textContent = 'Board ID not found. Please refresh the page and try again.'; addProjectResultEl.className = 'n88-result error'; }
                            return;
                        }
                        
                        addProjectSubmitBtn.disabled = true;
                        var prevProjectBtnText = addProjectSubmitBtn.textContent;
                        addProjectSubmitBtn.textContent = 'Creating...';
                        if (addProjectResultEl) { addProjectResultEl.textContent = ''; addProjectResultEl.className = 'n88-result'; }
                        
                        var formData = new FormData();
                        formData.append('action', 'n88_create_board_project');
                        formData.append('board_id', boardId);
                        formData.append('name', projectName);
                        formData.append('_ajax_nonce', nonce);
                        var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '/wp-admin/admin-ajax.php';
                        
                        fetch(ajaxUrl, { method: 'POST', body: formData })
                        .then(function(response) { return response.json(); })
                        .then(function(data) {
                            addProjectSubmitBtn.disabled = false;
                            addProjectSubmitBtn.textContent = prevProjectBtnText || '[ Create Project ]';
                            if (data.success) {
                                closeAddProjectModal();
                                var newProjectId = data.data && data.data.project_id ? data.data.project_id : null;
                                if (newProjectId) {
                                    var cur = new URLSearchParams(window.location.search);
                                    cur.set('project_id', String(newProjectId));
                                    cur.delete('room_id');
                                    window.location.search = cur.toString();
                                } else {
                                    window.location.reload();
                                }
                            } else {
                                if (addProjectResultEl) { addProjectResultEl.textContent = 'Error: ' + (data.data && data.data.message ? data.data.message : 'Failed to create project'); addProjectResultEl.className = 'n88-result error'; }
                            }
                        })
                        .catch(function(error) {
                            addProjectSubmitBtn.disabled = false;
                            addProjectSubmitBtn.textContent = prevProjectBtnText || '[ Create Project ]';
                            console.error('Error creating project:', error);
                            if (addProjectResultEl) { addProjectResultEl.textContent = 'An error occurred. Please try again.'; addProjectResultEl.className = 'n88-result error'; }
                        });
                    });
                }
                
                // Commit 2.5.2: Project selector change handler
                var projectSelector = document.getElementById('n88-project-selector');
                if (projectSelector) {
                    projectSelector.addEventListener('change', function() {
                        var projectId = this.value;
                        var urlParams = new URLSearchParams(window.location.search);
                        
                        if (projectId) {
                            urlParams.set('project_id', projectId);
                            // Remove room_id when switching projects
                            urlParams.delete('room_id');
                            // Add body class for spacing
                            document.body.classList.add('has-project-selected');
                        } else {
                            urlParams.delete('project_id');
                            urlParams.delete('room_id');
                            // Remove body class
                            document.body.classList.remove('has-project-selected');
                        }
                        
                        // Reload page with project filter
                        window.location.search = urlParams.toString();
                    });
                }
                
                // Fix 3: Room tab switching handler
                var roomTabs = document.querySelectorAll('.n88-room-tab');
                roomTabs.forEach(function(tab) {
                    tab.addEventListener('click', function(e) {
                        // Don't trigger if clicking edit/delete buttons
                        if (e.target.classList.contains('n88-edit-room-btn') || e.target.classList.contains('n88-delete-room-btn')) {
                            return;
                        }
                        
                        var roomId = this.getAttribute('data-room-id');
                        var urlParams = new URLSearchParams(window.location.search);
                        
                        // Update active tab styling
                        roomTabs.forEach(function(t) {
                            if (t.getAttribute('data-room-id') === roomId) {
                                t.style.backgroundColor = '#0073aa';
                                t.style.color = '#fff';
                            } else {
                                t.style.backgroundColor = '#f0f0f0';
                                t.style.color = '#666';
                            }
                        });
                        
                        // Update URL with room filter
                        if (roomId && roomId !== '0') {
                            urlParams.set('room_id', roomId);
                        } else {
                            urlParams.delete('room_id');
                        }
                        
                        // Reload page with room filter
                        window.location.search = urlParams.toString();
                    });
                });
                
                // Set active room tab on page load
                var urlParams = new URLSearchParams(window.location.search);
                var selectedRoomId = urlParams.get('room_id') || '0';
