                if (addRoomBackdrop) addRoomBackdrop.addEventListener('click', function(e) { if (e.target === addRoomBackdrop) closeAddRoomModal(); });
                
                if (addRoomSubmitBtn && addRoomNameInput) {
                    addRoomSubmitBtn.addEventListener('click', function() {
