                if (inviteSubmitBtn && inviteEmailInput) {
                    inviteSubmitBtn.addEventListener('click', function() {
                        var email = (inviteEmailInput.value || '').trim();
                        if (!email) {
                            if (inviteResultEl) { inviteResultEl.textContent = 'Please enter an email address.'; inviteResultEl.className = 'n88-result error'; }
                            return;
                        }
                        var emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                        if (!emailRegex.test(email)) {
                            if (inviteResultEl) { inviteResultEl.textContent = 'Please enter a valid email address.'; inviteResultEl.className = 'n88-result error'; }
                            return;
                        }
                        var nonce = (window.n88BoardNonce && window.n88BoardNonce.nonce_invite_team_member) || (window.n88BoardData && window.n88BoardData.nonce) || '';
                        if (!nonce) {
                            if (inviteResultEl) { inviteResultEl.textContent = 'Security token missing. Please refresh the page and try again.'; inviteResultEl.className = 'n88-result error'; }
                            return;
                        }
                        inviteSubmitBtn.disabled = true;
                        var prevInviteBtnText = inviteSubmitBtn.textContent;
                        inviteSubmitBtn.textContent = 'Sending...';
                        if (inviteResultEl) { inviteResultEl.textContent = ''; inviteResultEl.className = 'n88-result'; }
                        var formData = new FormData();
                        formData.append('action', 'n88_invite_team_member');
                        formData.append('email', email);
                        formData.append('_ajax_nonce', nonce);
                        var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '/wp-admin/admin-ajax.php';
                        fetch(ajaxUrl, { method: 'POST', body: formData })
                        .then(function(response) { return response.json(); })
                        .then(function(data) {
                            inviteSubmitBtn.disabled = false;
                            inviteSubmitBtn.textContent = prevInviteBtnText || '[ Invite Team Member ]';
                            if (data.success) {
                                if (inviteResultEl) { inviteResultEl.textContent = 'Invitation sent successfully to ' + email + '!'; inviteResultEl.className = 'n88-result success'; }
                                setTimeout(function() { closeInviteTeamMemberModal(); }, 1500);
                            } else {
                                if (inviteResultEl) { inviteResultEl.textContent = (data.data && data.data.message) ? data.data.message : 'Failed to send invitation.'; inviteResultEl.className = 'n88-result error'; }
                            }
                        })
                        .catch(function(error) {
                            inviteSubmitBtn.disabled = false;
                            inviteSubmitBtn.textContent = prevInviteBtnText || '[ Invite Team Member ]';
                            console.error('Error inviting team member:', error);
                            if (inviteResultEl) { inviteResultEl.textContent = 'Error sending invitation. Please try again.'; inviteResultEl.className = 'n88-result error'; }
                        });
                    });
                }
                }
                if (document.readyState === 'loading') {
                    document.addEventListener('DOMContentLoaded', initAddProjectAndRoomModals);
                } else {
                    initAddProjectAndRoomModals();
                }
                
                // Edit Room handlers
                var editRoomBtns = document.querySelectorAll('.n88-edit-room-btn');
                editRoomBtns.forEach(function(btn) {
                    btn.addEventListener('click', function(e) {
                        e.stopPropagation();
                        var roomId = this.getAttribute('data-room-id');
                        var currentName = this.getAttribute('data-room-name');
                        var newName = prompt('Enter new room name:', currentName);
                        
                        if (!newName || !newName.trim() || newName === currentName) {
                            return;
                        }
                        
                        newName = newName.trim();
                        
                        // Get nonce
                        var nonce = '';
                        if (window.n88BoardNonce && window.n88BoardNonce.nonce) {
                            nonce = window.n88BoardNonce.nonce;
                        } else if (window.n88BoardData && window.n88BoardData.nonce) {
                            nonce = window.n88BoardData.nonce;
                        }
                        
                        if (!nonce) {
                            alert('Security token missing. Please refresh the page and try again.');
                            return;
                        }
                        
                        var formData = new FormData();
                        formData.append('action', 'n88_update_project_room');
                        formData.append('room_id', roomId);
                        formData.append('name', newName);
                        formData.append('_ajax_nonce', nonce);
                        
                        var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '/wp-admin/admin-ajax.php';
                        
                        fetch(ajaxUrl, {
                            method: 'POST',
                            body: formData
                        })
                        .then(function(response) {
                            return response.json();
                        })
                        .then(function(data) {
                            if (data.success) {
                                alert('Room updated successfully!');
                                window.location.reload();
                            } else {
                                alert('Error: ' + (data.data.message || 'Failed to update room'));
                            }
                        })
                        .catch(function(error) {
                            console.error('Error updating room:', error);
                            alert('An error occurred. Please try again.');
                        });
                    });
                });
                
                // Delete Room handlers
                var deleteRoomBtns = document.querySelectorAll('.n88-delete-room-btn');
                deleteRoomBtns.forEach(function(btn) {
                    btn.addEventListener('click', function(e) {
                        e.stopPropagation();
                        var roomId = this.getAttribute('data-room-id');
                        
                        if (!confirm('Are you sure you want to delete this room? All items in this room will be removed from the board and the room will be deleted.')) {
                            return;
                        }
                        
                        // Get nonce
                        var nonce = '';
                        if (window.n88BoardNonce && window.n88BoardNonce.nonce) {
                            nonce = window.n88BoardNonce.nonce;
                        } else if (window.n88BoardData && window.n88BoardData.nonce) {
                            nonce = window.n88BoardData.nonce;
                        }
                        
                        if (!nonce) {
                            alert('Security token missing. Please refresh the page and try again.');
                            return;
                        }
                        
                        var formData = new FormData();
                        formData.append('action', 'n88_delete_project_room');
                        formData.append('room_id', roomId);
                        formData.append('_ajax_nonce', nonce);
                        
                        var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '/wp-admin/admin-ajax.php';
                        
                        fetch(ajaxUrl, {
                            method: 'POST',
                            body: formData
                        })
                        .then(function(response) {
                            return response.json();
                        })
                        .then(function(data) {
                            if (data.success) {
                                alert('Room deleted successfully!');
                                window.location.reload();
                            } else {
                                alert('Error: ' + (data.data.message || 'Failed to delete room'));
                            }
                        })
                        .catch(function(error) {
                            console.error('Error deleting room:', error);
                            alert('An error occurred. Please try again.');
                        });
                    });
                });
                
                // Delete Project button handler
                var deleteProjectBtn = document.getElementById('n88-delete-project-btn');
                if (deleteProjectBtn) {
                    deleteProjectBtn.addEventListener('click', function() {
                        var projectId = this.getAttribute('data-project-id') || document.getElementById('n88-project-selector').value;
                        if (!projectId || projectId === '') {
                            alert('Please select a project first.');
                            return;
                        }
                        if (!confirm('Are you sure you want to delete this project? All rooms and items in this project will be permanently removed.')) {
                            return;
                        }
                        var nonce = (window.n88BoardNonce && window.n88BoardNonce.nonce) || (window.n88BoardData && window.n88BoardData.nonce) || '';
                        if (!nonce) {
                            alert('Security token missing. Please refresh the page and try again.');
                            return;
                        }
                        var formData = new FormData();
                        formData.append('action', 'n88_delete_board_project');
                        formData.append('project_id', projectId);
                        formData.append('_ajax_nonce', nonce);
                        var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '/wp-admin/admin-ajax.php';
                        fetch(ajaxUrl, { method: 'POST', body: formData })
                            .then(function(r) { return r.json(); })
                            .then(function(data) {
                                if (data.success) {
                                    alert('Project deleted successfully.');
                                    var u = new URLSearchParams(window.location.search);
                                    u.delete('project_id');
                                    u.delete('room_id');
                                    window.location.href = window.location.pathname + (u.toString() ? '?' + u.toString() : '');
                                } else {
                                    alert('Error: ' + (data.data && data.data.message ? data.data.message : 'Failed to delete project.'));
                                }
                            })
                            .catch(function(err) {
                                console.error('Error deleting project:', err);
                                alert('An error occurred. Please try again.');
                            });
                    });
                }
                
                // Add body class to prevent scrolling
                if (document.body) {
                    document.body.classList.add('n88-board-page');
                }
                
                // SIMPLE: Just prevent focus from causing scroll - this is the main issue
                var canvasContainer = document.getElementById('n88-board-canvas-container');
                if (canvasContainer) {
                    // CRITICAL: Prevent focus from scrolling - buttons/inputs cause scroll jumps
                    canvasContainer.addEventListener('focusin', function(e) {
                        // Prevent any focus from causing scroll
                        e.preventDefault();
                        e.stopPropagation();
                    }, true);
                    
                    // Prevent wheel events from scrolling page when over canvas
                    canvasContainer.addEventListener('wheel', function(e) {
                        var isAtTop = canvasContainer.scrollTop <= 0;
                        var isAtBottom = canvasContainer.scrollTop >= canvasContainer.scrollHeight - canvasContainer.clientHeight - 1;
                        
                        if (!isAtTop && !isAtBottom) {
                            e.stopPropagation();
                        }
                    }, { passive: false });
                }
                
                // Completely disable page scroll - only canvas should scroll
                window.addEventListener('scroll', function(e) {
                    // Prevent page scroll, only allow canvas scroll
                    if (window.pageYOffset > 0) {
                        window.scrollTo(0, 0);
                    }
                }, { passive: false });
                
                // Lock page scroll on load
                setTimeout(function() {
                    window.scrollTo(0, 0);
                    document.documentElement.scrollTop = 0;
                    document.body.scrollTop = 0;
                }, 100);
            })();
            </script>
            
            <!-- Board Canvas Container - Fixed height, horizontal scroll only -->
            <div id="n88-board-canvas-container">
                <div id="n88-board-demo-root"></div>
            </div>
            
