            <script>
            (function() {
                var addItemBackdrop = document.getElementById('n88-add-item-modal-backdrop');
                if (addItemBackdrop && addItemBackdrop.parentNode && addItemBackdrop.parentNode !== document.body) document.body.appendChild(addItemBackdrop);
                var addItemBtn = document.getElementById('n88-add-item-btn');
                var backdrop = document.getElementById('n88-add-item-modal-backdrop');
                var closeBtn = document.getElementById('n88-add-item-modal-close');
                var modal = document.getElementById('n88-add-item-modal');
                var form = document.getElementById('n88-add-item-modal-form');
                var submitBtn = document.getElementById('n88-modal-add-item-submit');
                var addAnotherBtn = document.getElementById('n88-modal-add-another-item');
                var submitRfqDirectBtn = document.getElementById('n88-modal-submit-rfq-direct');
                var resultEl = document.getElementById('n88-add-item-modal-result');
                var pendingCreateSubmitRfq = false;
                function populateCategorySelect(selectEl, selectedValue) {
                    if (!selectEl) return;
                    var currentValue = selectedValue !== undefined ? selectedValue : (selectEl.value || '');
                    selectEl.innerHTML = '';
                    var placeholder = document.createElement('option');
                    placeholder.value = '';
                    placeholder.textContent = 'Select the closest category for accurate routing and quoting.';
                    selectEl.appendChild(placeholder);
                    (window.n88DesignerCategoryOptions || []).forEach(function(categoryName) {
                        var option = document.createElement('option');
                        option.value = categoryName;
                        option.textContent = categoryName;
                        if (String(currentValue || '') === String(categoryName)) option.selected = true;
                        selectEl.appendChild(option);
                    });
                }
                function renderKeywordChipsIntoWrap(wrap, keywords, selectedIds, onToggle) {
                    if (!wrap) return;
                    wrap.innerHTML = '';
                    if (!keywords || !keywords.length) {
                        wrap.innerHTML = '<div style="font-size:11px;color:#888;">No keywords available for this category.</div>';
                        return;
                    }
                    keywords.forEach(function(keyword) {
                        var keywordId = parseInt(keyword.keyword_id, 10);
                        var isSelected = selectedIds.indexOf(keywordId) !== -1;
                        var button = document.createElement('button');
                        button.type = 'button';
                        button.textContent = keyword.keyword || '';
                        button.style.cssText = 'padding:6px 10px;border-radius:999px;border:1px solid ' + (isSelected ? '#FF0065' : '#333') + ';background:' + (isSelected ? 'rgba(255,0,101,0.14)' : '#111') + ';color:' + (isSelected ? '#fff' : '#d3d3d3') + ';font-size:11px;font-family:monospace;cursor:pointer;';
                        button.onclick = function() { onToggle(keywordId); };
                        wrap.appendChild(button);
                    });
                }
                function initKeywordControlsForBlock(block) {
                    if (!block) return;
                    if (!Array.isArray(block.n88SelectedKeywordIds)) block.n88SelectedKeywordIds = [];
                    var categoryEl = block.querySelector('[name="item_type"]');
                    var keywordsWrap = block.querySelector('.n88-item-keywords-wrap');
                    if (!categoryEl || !keywordsWrap) return;
                    populateCategorySelect(categoryEl, categoryEl.value || '');
                    function renderKeywordLoading(message) {
                        keywordsWrap.innerHTML = '';
                        var loadingEl = document.createElement('div');
                        loadingEl.textContent = message || 'Loading keywords...';
                        loadingEl.style.fontSize = '11px';
                        loadingEl.style.opacity = '0.75';
                        loadingEl.style.padding = '4px 0';
                        keywordsWrap.appendChild(loadingEl);
                    }
                    function renderKeywords() {
                        if (!(categoryEl.value || '').trim()) {
                            keywordsWrap.innerHTML = '';
                            return;
                        }
                        renderKeywordLoading('Loading keywords...');
                        window.n88LoadCategoryKeywords(categoryEl.value || '').then(function(keywords) {
                            renderKeywordChipsIntoWrap(keywordsWrap, keywords, block.n88SelectedKeywordIds, function(keywordId) {
                                var idx = block.n88SelectedKeywordIds.indexOf(keywordId);
                                if (idx !== -1) block.n88SelectedKeywordIds.splice(idx, 1);
                                else block.n88SelectedKeywordIds.push(keywordId);
                                renderKeywords();
                            });
                        }).catch(function() {
                            renderKeywordLoading('Unable to load keywords.');
                        });
                    }
                    if (!block._n88KeywordsInit) {
                        block._n88KeywordsInit = true;
                        categoryEl.addEventListener('change', function() {
                            block.n88SelectedKeywordIds = [];
                            renderKeywords();
                        });
                    }
                    renderKeywords();
                }
                function applyMeasurementTypeToBlock(block, nextType) {
                    if (!block) return;
                    var categoryEl = block.querySelector('[name="item_type"]');
                    var typeEl = block.querySelector('[name="measurement_type"]');
                    var effectiveType = n88GetEffectiveMeasurementType(nextType || (typeEl ? typeEl.value : ''), categoryEl ? categoryEl.value : '');
                    if (typeEl) typeEl.value = effectiveType;
                    var groups = block.querySelectorAll('.n88-measurement-group');
                    groups.forEach(function(group) {
                        group.style.display = group.getAttribute('data-measurement-group') === effectiveType ? '' : 'none';
                    });
                }
                function initMeasurementControlsForBlock(block) {
                    if (!block || block._n88MeasurementInit) return;
                    block._n88MeasurementInit = true;
                    var categoryEl = block.querySelector('[name="item_type"]');
                    var typeEl = block.querySelector('[name="measurement_type"]');
                    if (categoryEl) {
                        categoryEl.addEventListener('change', function() {
                            applyMeasurementTypeToBlock(block, categoryEl.value);
                        });
                    }
                    if (typeEl) {
                        typeEl.addEventListener('change', function() {
                            applyMeasurementTypeToBlock(block, typeEl.value);
                        });
                    }
                    initKeywordControlsForBlock(block);
                    applyMeasurementTypeToBlock(block, categoryEl ? categoryEl.value : (typeEl ? typeEl.value : ''));
                }
                function getMeasurementPayloadFromBlock(block) {
                    var typeEl = block ? block.querySelector('[name="measurement_type"]') : null;
                    var categoryEl = block ? block.querySelector('[name="item_type"]') : null;
                    var type = n88GetEffectiveMeasurementType(typeEl ? typeEl.value : '', categoryEl ? categoryEl.value : '');
                    var payload = { measurement_type: type };
                    payload.selected_keyword_ids = Array.isArray(block.n88SelectedKeywordIds) ? block.n88SelectedKeywordIds.slice() : [];
                    if (type === 'dimensions') {
                        var w = (block.querySelector('[name="width"]') || {}).value;
                        var d = (block.querySelector('[name="depth"]') || {}).value;
                        var h = (block.querySelector('[name="height"]') || {}).value;
                        var unit = (block.querySelector('[name="dimension_unit"]') || {}).value || 'in';
                        payload.width = w;
                        payload.depth = d;
                        payload.height = h;
                        payload.dimension_unit = unit;
                        if (w || d || h) {
                            payload.dims = { w: w ? parseFloat(w) : null, d: d ? parseFloat(d) : null, h: h ? parseFloat(h) : null, unit: unit };
                        }
                    } else if (type === 'area') {
                        payload.measurement_area = (block.querySelector('[name="measurement_area"]') || {}).value || '';
                        payload.measurement_area_unit = (block.querySelector('[name="measurement_area_unit"]') || {}).value || 'sq_ft';
                    } else if (type === 'linear_length') {
                        payload.measurement_length = (block.querySelector('[name="measurement_length"]') || {}).value || '';
                        payload.measurement_length_unit = (block.querySelector('[name="measurement_length_unit"]') || {}).value || 'ft';
                    } else if (type === 'custom_specification') {
                        payload.custom_specification = (block.querySelector('[name="custom_specification"]') || {}).value || '';
                    }
                    return payload;
                }
                
                function openAddItemModal() {
                    if (backdrop) {
                        backdrop.classList.add('n88-modal-open');
                        backdrop.setAttribute('aria-hidden', 'false');
                        document.body.classList.add('n88-modal-open');
                    }
                    if (form) form.style.display = '';
                    if (submitBtn) submitBtn.style.display = '';
                    if (addAnotherBtn) addAnotherBtn.style.display = '';
                    if (submitRfqDirectBtn) submitRfqDirectBtn.style.display = 'none';
                    if (resultEl) { resultEl.style.display = ''; }
                    var reqOnlyBtnOpen = document.getElementById('n88-modal-request-quote-now-only');
                    if (reqOnlyBtnOpen) reqOnlyBtnOpen.style.display = 'none';
                    if (form) {
                        var marked = form.querySelectorAll('.n88-rfq-missing');
                        marked.forEach(function(el) {
                            el.classList.remove('n88-rfq-missing');
                            el.style.borderColor = '';
                            el.style.boxShadow = '';
                        });
                    }
                    updateDirectRfqButtonVisibility();
                }
                if (form) {
                    form.addEventListener('change', function(e) {
                        var target = e.target;
                        if (!target || !target.name) return;
                        var block = target.closest('.n88-add-item-block') || form;
                        if (target.name === 'item_type') {
                            applyMeasurementTypeToBlock(block, target.value);
                        } else if (target.name === 'measurement_type') {
                            applyMeasurementTypeToBlock(block, target.value);
                        }
                    });
                }
                function closeAddItemModal() {
                    if (backdrop) {
                        backdrop.classList.remove('n88-modal-open');
                        backdrop.setAttribute('aria-hidden', 'true');
                        document.body.classList.remove('n88-modal-open');
                    }
                    var reqOnlyBtnClose = document.getElementById('n88-modal-request-quote-now-only');
                    if (reqOnlyBtnClose) reqOnlyBtnClose.style.display = 'none';
                    resetAddItemModalState();
                }
                
                if (addItemBtn) addItemBtn.addEventListener('click', openAddItemModal);
                if (closeBtn) closeBtn.addEventListener('click', closeAddItemModal);
                if (backdrop) {
                    backdrop.addEventListener('click', function(e) {
                        if (e.target === backdrop) closeAddItemModal();
                    });
                }
                if (modal) modal.addEventListener('click', function(e) { e.stopPropagation(); });

                var blocksContainer = document.getElementById('n88-add-item-blocks');
                function getNextBlockIndex() {
                    var blocks = blocksContainer ? blocksContainer.querySelectorAll('.n88-add-item-block') : [];
                    return blocks.length + 1;
                }
                function toggleBlock(blockEl) {
                    if (!blockEl || !blockEl.classList) return;
                    blockEl.classList.toggle('n88-item-block-expanded');
                    blockEl.classList.toggle('n88-item-block-collapsed');
                    var header = blockEl.querySelector('.n88-item-block-header');
                    if (header) header.setAttribute('aria-expanded', blockEl.classList.contains('n88-item-block-expanded'));
                }
                if (blocksContainer) {
                    blocksContainer.addEventListener('click', function(e) {
                        var header = e.target.closest('.n88-item-block-header');
                        if (header) {
                            var block = header.closest('.n88-add-item-block');
                            toggleBlock(block);
                        }
                    });
                }

                var qtyInput = document.getElementById('n88-modal-item-quantity');
                var qtyMinus = document.getElementById('n88-modal-qty-minus');
                var qtyPlus = document.getElementById('n88-modal-qty-plus');
                if (form) {
                    form.addEventListener('click', function(e) {
                        var isMinus = e.target.id === 'n88-modal-qty-minus' || e.target.closest('#n88-modal-qty-minus');
                        var isPlus = e.target.id === 'n88-modal-qty-plus' || e.target.closest('#n88-modal-qty-plus');
                        if (!isMinus && !isPlus) return;
                        var block = e.target.closest('.n88-add-item-block');
                        var inp = block ? block.querySelector('input[name="quantity"]') : document.getElementById('n88-modal-item-quantity');
                        if (!inp) return;
                        var v = parseInt(inp.value, 10) || 1;
                        if (isMinus && v > 1) inp.value = v - 1;
                        if (isPlus) inp.value = v + 1;
                    });
                }
                if (qtyMinus && qtyInput) qtyMinus.addEventListener('click', function() {
                    var v = parseInt(qtyInput.value, 10) || 1;
                    if (v > 1) qtyInput.value = v - 1;
                });
                if (qtyPlus && qtyInput) qtyPlus.addEventListener('click', function() {
                    var v = parseInt(qtyInput.value, 10) || 1;
                    qtyInput.value = v + 1;
                });
                
                var uploadZone = document.getElementById('n88-modal-upload-zone');
                var uploadText = document.getElementById('n88-modal-upload-text');
                var fileInput = document.getElementById('n88-modal-item-image-file');
                var previewWrap = document.getElementById('n88-modal-image-preview-wrap');
                var defaultUploadLabel = 'Upload sketches, inspiration photos, shop drawings, or material references';
                var n88ModalSelectedFiles = [];
                var n88ModalCaptions = [];
                var n88ModalPrimaryIndex = 0;

                function resetAddItemModalState() {
                    if (form) {
                        try { form.reset(); } catch (e) {}
                    }
                    if (resultEl) {
                        resultEl.textContent = '';
                        resultEl.className = 'n88-result';
                        resultEl.style.display = '';
                    }
                    if (submitBtn) {
                        submitBtn.disabled = false;
                        submitBtn.style.display = '';
                        submitBtn.innerHTML = submitBtn.getAttribute('data-default-text') || '[ Add Item ]';
                    }
                    if (addAnotherBtn) {
                        addAnotherBtn.style.display = '';
                    }
                    if (submitRfqDirectBtn) {
                        submitRfqDirectBtn.disabled = false;
                        submitRfqDirectBtn.style.display = 'none';
                        submitRfqDirectBtn.textContent = submitRfqDirectBtn.getAttribute('data-default-text') || '[ Submit RFQ ]';
                    }
                    var overlay = document.getElementById('n88-add-item-postsave');
                    if (overlay && overlay.parentNode) {
                        overlay.parentNode.removeChild(overlay);
                    }
                    if (blocksContainer) {
                        var blocks = blocksContainer.querySelectorAll('.n88-add-item-block');
                        for (var i = 1; i < blocks.length; i++) {
                            blocks[i].remove();
                        }
                        var firstBlock = blocksContainer.querySelector('.n88-add-item-block');
                        if (firstBlock) {
                            firstBlock.classList.add('n88-item-block-expanded');
                            firstBlock.classList.remove('n88-item-block-collapsed');
                            var firstHeader = firstBlock.querySelector('.n88-item-block-header');
                            if (firstHeader) firstHeader.setAttribute('aria-expanded', 'true');

                            firstBlock.n88Files = [];
                            firstBlock.n88Captions = [];
                            firstBlock.n88PrimaryIndex = 0;
                            firstBlock.n88InvitedSuppliers = [];
                            firstBlock.n88SelectedKeywordIds = [];
                            firstBlock.n88SyncDeliveryFromFirst = false;
                            firstBlock.n88SyncSuppliersFromFirst = false;

                            var chipsWrap = firstBlock.querySelector('.n88-invite-chips');
                            if (chipsWrap) chipsWrap.innerHTML = '';
                            var allowSystemBox = firstBlock.querySelector('.n88-allow-system-invites');
                            if (allowSystemBox) {
                                allowSystemBox.checked = false;
                                allowSystemBox.disabled = false;
                            }
                            var deliverySyncBox = firstBlock.querySelector('.n88-sync-delivery-from-first');
                            var suppliersSyncBox = firstBlock.querySelector('.n88-sync-suppliers-from-first');
                            if (deliverySyncBox) deliverySyncBox.checked = false;
                            if (suppliersSyncBox) suppliersSyncBox.checked = false;

                            var blockFileInput = firstBlock.querySelector('input[type="file"]');
                            if (blockFileInput) blockFileInput.value = '';
                            var blockUploadZone = firstBlock.querySelector('.n88-upload-zone');
                            if (blockUploadZone) blockUploadZone.classList.remove('has-file');
                            var blockUploadText = firstBlock.querySelector('.n88-upload-text, [id$="upload-text"]');
                            if (blockUploadText) blockUploadText.textContent = defaultUploadLabel;
                            renderPreviewsForBlock(firstBlock, []);

                            var roomSel = firstBlock.querySelector('select[name="room_id"]');
                            var roomField = roomSel ? roomSel.closest('.n88-field') : null;
                            if (roomSel) roomSel.innerHTML = '<option value="">Select Room</option>';
                            if (roomField) roomField.style.display = 'none';
                            initIntegerDimensionInputsForBlock(firstBlock);
                            if (typeof firstBlock.n88RenderInviteChips === 'function') {
                                firstBlock.n88RenderInviteChips();
                            }
                            refreshMultiItemSharedFieldSync();
                        }
                    }
                    n88ModalSelectedFiles = [];
                    n88ModalCaptions = [];
                    n88ModalPrimaryIndex = 0;
                    if (uploadZone) uploadZone.classList.remove('has-file');
                    if (uploadText) uploadText.textContent = defaultUploadLabel;
                    if (fileInput) fileInput.value = '';
                    if (previewWrap) {
                        previewWrap.innerHTML = '';
                        previewWrap.classList.remove('visible');
                    }
                    if (form) {
                        var marked = form.querySelectorAll('.n88-rfq-missing');
                        marked.forEach(function(el) {
                            el.classList.remove('n88-rfq-missing');
                            el.style.borderColor = '';
                            el.style.boxShadow = '';
                        });
                    }
                    pendingCreateSubmitRfq = false;
                }

                function updatePrimaryBadgesDefault() {
                    if (!previewWrap) return;
                    var items = previewWrap.querySelectorAll('.n88-preview-item');
                    items.forEach(function(el, idx) {
                        if (idx === n88ModalPrimaryIndex) {
                            el.classList.add('n88-primary-selected');
                        } else {
                            el.classList.remove('n88-primary-selected');
                        }
                    });
                }

                function clearMissingMark(el) {
                    if (!el) return;
                    el.classList.remove('n88-rfq-missing');
                    el.style.borderColor = '';
                    el.style.boxShadow = '';
                }

                function isInviteValidForBlock(block) {
                    if (!block) return true;
                    var allowBox = block.querySelector('.n88-allow-system-invites');
                    if (allowBox && allowBox.checked) return true;
                    var chipsWrap = block.querySelector('.n88-invite-chips');
                    if (!chipsWrap) return false;
                    return chipsWrap.querySelectorAll('span[data-supplier]').length > 0;
                }

                function isMissingFieldResolved(el) {
                    if (!el) return true;
                    var block = el.closest('.n88-add-item-block');
                    var tag = (el.tagName || '').toLowerCase();
                    var name = el.getAttribute('name') || '';

                    if (el.classList.contains('n88-invite-input')) {
                        return isInviteValidForBlock(block);
                    }
                    if (name === 'title' || name === 'description' || name === 'item_type') {
                        return !!(el.value && el.value.trim());
                    }
                    if (name === 'quantity' || name === 'width' || name === 'depth' || name === 'height') {
                        var num = parseFloat(el.value);
                        return !!(num && num > 0);
                    }
                    if (name === 'delivery_country') {
                        return !!(el.value && String(el.value).trim());
                    }
                    if (name === 'delivery_postal') {
                        var countrySel = block ? block.querySelector('select[name="delivery_country"]') : null;
                        var countryVal = countrySel && countrySel.value ? String(countrySel.value).toUpperCase().trim() : '';
                        if (countryVal === 'US' || countryVal === 'CA') {
                            return !!(el.value && el.value.trim());
                        }
                        return true;
                    }
                    if (tag === 'input' || tag === 'textarea' || tag === 'select') {
                        return !!(el.value && String(el.value).trim());
                    }
                    return true;
                }

                function refreshRfqMissingState() {
                    if (!form) return;
                    var marked = form.querySelectorAll('.n88-rfq-missing');
                    marked.forEach(function(el) {
                        if (isMissingFieldResolved(el)) {
                            clearMissingMark(el);
                        }
                    });
                    var remaining = form.querySelectorAll('.n88-rfq-missing');
                    if (remaining.length === 0 && resultEl && resultEl.classList.contains('error')) {
                        resultEl.textContent = '';
                        resultEl.className = 'n88-result';
                    }
                }

                function renderAddItemPreviews() {
                    if (!previewWrap) return;
                    previewWrap.innerHTML = '';
                    for (var i = 0; i < n88ModalSelectedFiles.length; i++) {
                        (function(idx) {
                            var file = n88ModalSelectedFiles[idx];
                            var name = (file.name || '').toLowerCase();
                            var isHeic = name.endsWith('.heic') || name.endsWith('.heif');
                            var wrap = document.createElement('div');
                            wrap.className = 'n88-preview-item';
                            if (!isHeic && file.type.indexOf('image/') === 0) {
                                var url = URL.createObjectURL(file);
                                var img = document.createElement('img');
                                img.src = url;
                                img.alt = 'Preview ' + (idx + 1);
                                img.onload = function() { URL.revokeObjectURL(url); };
                                wrap.appendChild(img);
                            } else {
                                var place = document.createElement('div');
                                place.style.cssText = 'width:80px;height:80px;background:#222;color:#888;font-size:10px;display:flex;align-items:center;justify-content:center;border-radius:4px;';
                                place.textContent = '[img]';
                                wrap.appendChild(place);
                            }

                            // Primary photo selector (only when multiple images)
                            if (n88ModalSelectedFiles.length > 1) {
                                var primaryBtn = document.createElement('button');
                                primaryBtn.type = 'button';
                                primaryBtn.className = 'n88-preview-primary';
                                primaryBtn.textContent = 'Primary';
                                primaryBtn.onclick = function() {
                                    n88ModalPrimaryIndex = idx;
                                    updatePrimaryBadgesDefault();
                                };
                                wrap.appendChild(primaryBtn);
                            }

                            // Remove button
                            var btn = document.createElement('button');
                            btn.type = 'button';
                            btn.className = 'n88-preview-remove';
                            btn.setAttribute('aria-label', 'Remove');
                            btn.textContent = '\u00D7';
                            btn.onclick = function() {
                                n88ModalSelectedFiles.splice(idx, 1);
                                if (n88ModalCaptions.length > idx) {
                                    n88ModalCaptions.splice(idx, 1);
                                }
                                if (n88ModalPrimaryIndex === idx) {
                                    n88ModalPrimaryIndex = 0;
                                } else if (n88ModalPrimaryIndex > idx) {
                                    n88ModalPrimaryIndex--;
                                }
                                renderAddItemPreviews();
                                if (uploadText) uploadText.textContent = n88ModalSelectedFiles.length === 0 ? defaultUploadLabel : (n88ModalSelectedFiles.length + ' files selected');
                                if (uploadZone) uploadZone.classList.toggle('has-file', n88ModalSelectedFiles.length > 0);
                            };
                            wrap.appendChild(btn);

                            // Caption input (per-image notes, max 100 chars)
                            var captionInput = document.createElement('input');
                            captionInput.type = 'text';
                            captionInput.className = 'n88-preview-caption';
                            captionInput.maxLength = 100;
                            captionInput.placeholder = 'Notes (max 100)';
                            captionInput.value = (n88ModalCaptions[idx] || '').slice(0, 100);
                            captionInput.oninput = function(e) {
                                n88ModalCaptions[idx] = (e.target.value || '').slice(0, 100);
                            };
                            wrap.appendChild(captionInput);

                            previewWrap.appendChild(wrap);
                        })(i);
                    }
                    previewWrap.classList.toggle('visible', n88ModalSelectedFiles.length > 0);
                    if (n88ModalSelectedFiles.length > 0 && (n88ModalPrimaryIndex < 0 || n88ModalPrimaryIndex >= n88ModalSelectedFiles.length)) {
                        n88ModalPrimaryIndex = 0;
                    }
                    updatePrimaryBadgesDefault();
                }
                if (uploadZone && fileInput) {
                    uploadZone.addEventListener('click', function() { fileInput.click(); });
                    fileInput.addEventListener('change', function() {
                        var files = fileInput.files;
                        if (files && files.length > 0) {
                            for (var j = 0; j < files.length; j++) {
                                n88ModalSelectedFiles.push(files[j]);
                                n88ModalCaptions.push('');
                            }
                            fileInput.value = '';
                            uploadZone.classList.add('has-file');
                            if (uploadText) uploadText.textContent = n88ModalSelectedFiles.length === 1 ? n88ModalSelectedFiles[0].name : (n88ModalSelectedFiles.length + ' files selected');
                            renderAddItemPreviews();
                        }
                    });
                }
                
                var projectSelect = document.getElementById('n88-modal-item-project');
                var roomRow = document.getElementById('n88-modal-room-row');
                var roomSelect = document.getElementById('n88-modal-item-room');
                function loadRoomsForBlock(block, projectId) {
                    if (!block || !projectId) return;
                    var roomSel = block.querySelector('select[name="room_id"]');
                    if (!roomSel) return;
                    var row = roomSel.closest('.n88-field');
                    if (!row) return;
                    row.style.display = projectId ? 'block' : 'none';
                    if (!projectId) { roomSel.innerHTML = '<option value="">Select Room</option>'; return; }
                    roomSel.innerHTML = '<option value="">Loading...</option>';
                    var nonce = (window.n88BoardNonce && window.n88BoardNonce.nonce) || (window.n88BoardData && window.n88BoardData.nonce) || '';
                    var ajaxUrl = (window.n88BoardData && window.n88BoardData.ajaxUrl) || (window.n88 && window.n88.ajaxUrl) || '<?php echo esc_js( admin_url( 'admin-ajax.php' ) ); ?>';
                    var url = ajaxUrl + '?action=n88_get_project_rooms&project_id=' + encodeURIComponent(projectId) + '&nonce=' + encodeURIComponent(nonce);
                    fetch(url).then(function(r) { return r.json(); }).then(function(res) {
                        var opts = '<option value="">Select Room</option>';
                        if (res.success && res.data && res.data.rooms) {
                            res.data.rooms.forEach(function(room) {
                                opts += '<option value="' + room.id + '">' + (room.name || '') + '</option>';
                            });
                        }
                        roomSel.innerHTML = opts;
                    }).catch(function() { roomSel.innerHTML = '<option value="">Error loading rooms</option>'; });
                }
                if (form) {
                    form.addEventListener('change', function(e) {
                        var target = e.target;
                        var targetBlock = target ? target.closest('.n88-add-item-block') : null;
                        if (e.target && e.target.getAttribute('name') === 'project_id') {
                            var block = e.target.closest('.n88-add-item-block');
                            loadRoomsForBlock(block, e.target.value);
                        }

                        // Fabric supplied radio: keep Fabric Notes visible for both Yes/No
                        if (e.target && e.target.getAttribute('data-rfq-fabric-flag')) {
                            var block = e.target.closest('.n88-add-item-block');
                            if (!block) return;
                            var notesWrap = block.querySelector('.n88-fabric-notes-wrap');
                            if (!notesWrap) return;
                            if (e.target.checked) {
                                notesWrap.style.display = '';
                            }
                        }
                        if (target && target.classList.contains('n88-sync-delivery-from-first')) {
                            applyDeliverySyncStateToBlock(targetBlock, !!target.checked);
                        }
                        if (target && target.classList.contains('n88-sync-delivery-date-from-first')) {
                            applyDeliveryDateSyncStateToBlock(targetBlock, !!target.checked);
                        }
                        if (target && target.classList.contains('n88-sync-suppliers-from-first')) {
                            applySupplierSyncStateToBlock(targetBlock, !!target.checked);
                        }
                        if (target && target.classList.contains('n88-sync-fabric-from-first')) {
                            applyFabricSyncStateToBlock(targetBlock, !!target.checked);
                        }
                        if (isFirstAddItemBlock(targetBlock)) {
                            var targetName = target && target.getAttribute ? (target.getAttribute('name') || '') : '';
                            if (
                                targetName === 'delivery_country' ||
                                targetName === 'delivery_postal' ||
                                targetName === 'preferred_delivery_date' ||
                                targetName === 'project_id' ||
                                targetName === 'room_id' ||
                                targetName.indexOf('rfq_fabric_supplied_flag') === 0 ||
                                targetName === 'rfq_fabric_notes' ||
                                (target && target.classList && target.classList.contains('n88-allow-system-invites'))
                            ) {
                                refreshMultiItemSharedFieldSync();
                            }
                        }
                        refreshRfqMissingState();
                        updateDirectRfqButtonVisibility();
                    });
                    form.addEventListener('input', function(e) {
                        var target = e.target;
                        var targetBlock = target ? target.closest('.n88-add-item-block') : null;
                        if (isFirstAddItemBlock(targetBlock)) {
                            var targetName = target && target.getAttribute ? (target.getAttribute('name') || '') : '';
                            if (
                                targetName === 'delivery_postal' ||
                                targetName === 'delivery_country' ||
                                targetName === 'preferred_delivery_date' ||
                                targetName === 'rfq_fabric_notes'
                            ) {
                                refreshMultiItemSharedFieldSync();
                            }
                        }
                        refreshRfqMissingState();
                        updateDirectRfqButtonVisibility();
                    });
                }
                if (projectSelect && roomRow && roomSelect) {
                    projectSelect.addEventListener('change', function() {
                        loadRoomsForBlock(projectSelect.closest('.n88-add-item-block'), projectSelect.value);
                    });
                }
                
                var addAnotherBtnInForm = document.getElementById('n88-modal-add-another-item');

                // Invite Suppliers helpers
                function initInviteControlsForBlock(block) {
                    if (!block) return;
                    var input = block.querySelector('.n88-invite-input');
                    var addBtn = block.querySelector('.n88-invite-add-btn');
                    var chipsWrap = block.querySelector('.n88-invite-chips');
                    if (!chipsWrap) return;

                    if (!Array.isArray(block.n88InvitedSuppliers)) {
                        block.n88InvitedSuppliers = [];
                    }

                    function renderChips() {
                        chipsWrap.innerHTML = '';
                        block.n88InvitedSuppliers.forEach(function(val) {
                            var chip = document.createElement('span');
                            chip.setAttribute('data-supplier', val);
                            chip.textContent = val;
                            chip.className = 'n88-invite-chip';
                            var removeBtn = document.createElement('button');
                            removeBtn.type = 'button';
                            removeBtn.textContent = 'x';
                            removeBtn.className = 'n88-invite-chip-remove';
                            removeBtn.onclick = function() {
                                block.n88InvitedSuppliers = block.n88InvitedSuppliers.filter(function(s) { return s !== val; });
                                renderChips();
                                if (isFirstAddItemBlock(block)) {
                                    refreshMultiItemSharedFieldSync();
                                }
                            };
                            chip.appendChild(removeBtn);
                            chipsWrap.appendChild(chip);
                        });
                        chipsWrap.querySelectorAll('.n88-invite-chip-remove').forEach(function(btn) {
                            btn.disabled = !!block.n88SyncSuppliersFromFirst;
                        });
                        refreshRfqMissingState();
                    }

                    function addInvite(value) {
                        var v = (value || '').trim();
                        if (!v) return;
                        if (block.n88InvitedSuppliers.indexOf(v) !== -1) return;
                        if (block.n88InvitedSuppliers.length >= 5) return;
                        block.n88InvitedSuppliers.push(v);
                        renderChips();
                        if (isFirstAddItemBlock(block)) {
                            refreshMultiItemSharedFieldSync();
                        }
                    }

                    if (addBtn) {
                        addBtn.onclick = function() {
                            if (input) {
                                addInvite(input.value);
                                input.value = '';
                            }
                        };
                    }
                    if (input) {
                        input.addEventListener('keypress', function(e) {
                            if (e.key === 'Enter') {
                                e.preventDefault();
                                addInvite(input.value);
                                input.value = '';
                            }
                        });
                    }

                    block.n88RenderInviteChips = renderChips;
                    renderChips();
                }

                function getFirstAddItemBlock() {
                    return blocksContainer ? blocksContainer.querySelector('.n88-add-item-block') : null;
                }

                function isFirstAddItemBlock(block) {
                    var firstBlock = getFirstAddItemBlock();
                    return !!(firstBlock && block && firstBlock === block);
                }

                function sanitizeIntegerDimensionValue(value) {
                    var raw = String(value == null ? '' : value);
                    var sanitized = raw.replace(/[^\d-]/g, '');
                    if (sanitized.indexOf('-') > 0) {
                        sanitized = sanitized.replace(/-/g, '');
                    }
                    if (sanitized.indexOf('-') === 0) {
                        sanitized = '-' + sanitized.slice(1).replace(/-/g, '');
                    }
                    return sanitized;
                }

                function enforceIntegerDimensionInput(input) {
                    if (!input || input.dataset.integerBound === '1') return;
                    input.dataset.integerBound = '1';
                    input.addEventListener('input', function() {
                        var sanitized = sanitizeIntegerDimensionValue(input.value);
                        if (input.value !== sanitized) {
                            input.value = sanitized;
                        }
                        refreshRfqMissingState();
                    });
                    input.addEventListener('keydown', function(e) {
                        if (e.key === '.' || e.key === ',' || e.key === 'e' || e.key === 'E') {
                            e.preventDefault();
                        }
                    });
                }

                function initIntegerDimensionInputsForBlock(block) {
                    if (!block) return;
                    ['width', 'depth', 'height'].forEach(function(name) {
                        enforceIntegerDimensionInput(block.querySelector('[name="' + name + '"]'));
                    });
                }

                function getDeliverySyncPayload(block) {
                    return {
                        delivery_country: ((block.querySelector('[name="delivery_country"]') || {}).value || ''),
                        delivery_postal: ((block.querySelector('[name="delivery_postal"]') || {}).value || '')
                    };
                }

                function getDeliveryDateSyncPayload(block) {
                    return {
                        preferred_delivery_date: ((block.querySelector('[name="preferred_delivery_date"]') || {}).value || '')
                    };
                }

                function getFabricSyncPayload(block) {
                    var fabricNoRadio = block.querySelector('input[name^="rfq_fabric_supplied_flag"][data-rfq-fabric-flag="no"]') || block.querySelector('input[name="rfq_fabric_supplied_flag"][data-rfq-fabric-flag="no"]');
                    return {
                        rfq_fabric_supplied_flag: fabricNoRadio && fabricNoRadio.checked ? 'no' : 'yes',
                        rfq_fabric_notes: ((block.querySelector('[name="rfq_fabric_notes"]') || {}).value || '')
                    };
                }

                function getSupplierSyncPayload(block) {
                    var allowSystemBox = block.querySelector('.n88-allow-system-invites');
                    return {
                        invited_suppliers: Array.isArray(block.n88InvitedSuppliers) ? block.n88InvitedSuppliers.slice() : [],
                        allow_system_invites: !!(allowSystemBox && allowSystemBox.checked)
                    };
                }

                function applyDeliverySyncStateToBlock(block, enabled) {
                    if (!block) return;
                    var countrySelect = block.querySelector('[name="delivery_country"]');
                    var postalInput = block.querySelector('[name="delivery_postal"]');
                    var deliveryField = countrySelect ? countrySelect.closest('.n88-field') : null;
                    var postalField = postalInput ? postalInput.closest('.n88-field') : null;
                    var lockTargets = [countrySelect, postalInput];
                    block.n88SyncDeliveryFromFirst = !!enabled;
                    if (deliveryField) deliveryField.classList.toggle('n88-sync-locked', !!enabled);
                    if (postalField) postalField.classList.toggle('n88-sync-locked', !!enabled);
                    if (!isFirstAddItemBlock(block) && enabled) {
                        var firstBlock = getFirstAddItemBlock();
                        if (firstBlock) {
                            var payload = getDeliverySyncPayload(firstBlock);
                            if (countrySelect) countrySelect.value = payload.delivery_country;
                            if (postalInput) postalInput.value = payload.delivery_postal;
                        }
                    }
                    lockTargets.forEach(function(el) {
                        if (!el) return;
                        el.disabled = !!enabled;
                    });
                }

                function applyDeliveryDateSyncStateToBlock(block, enabled) {
                    if (!block) return;
                    var dateInput = block.querySelector('[name="preferred_delivery_date"]');
                    var dateField = dateInput ? dateInput.closest('.n88-field') : null;
                    block.n88SyncDeliveryDateFromFirst = !!enabled;
                    if (dateField) dateField.classList.toggle('n88-sync-locked', !!enabled);
                    if (!isFirstAddItemBlock(block) && enabled) {
                        var firstBlock = getFirstAddItemBlock();
                        if (firstBlock && dateInput) {
                            var payload = getDeliveryDateSyncPayload(firstBlock);
                            dateInput.value = payload.preferred_delivery_date;
                        }
                    }
                    if (dateInput) {
                        dateInput.disabled = !!enabled;
                    }
                }

                function applyFabricSyncStateToBlock(block, enabled) {
                    if (!block) return;
                    var fabricRadios = block.querySelectorAll('input[name^="rfq_fabric_supplied_flag"], input[name="rfq_fabric_supplied_flag"]');
                    var fabricNotes = block.querySelector('[name="rfq_fabric_notes"]');
                    var fabricField = fabricNotes ? fabricNotes.closest('.n88-field') : null;
                    block.n88SyncFabricFromFirst = !!enabled;
                    if (fabricField) fabricField.classList.toggle('n88-sync-locked', !!enabled);
                    if (!isFirstAddItemBlock(block) && enabled) {
                        var firstBlock = getFirstAddItemBlock();
                        if (firstBlock) {
                            var payload = getFabricSyncPayload(firstBlock);
                            fabricRadios.forEach(function(radio) {
                                radio.checked = radio.getAttribute('data-rfq-fabric-flag') === payload.rfq_fabric_supplied_flag;
                            });
                            if (fabricNotes) {
                                fabricNotes.value = payload.rfq_fabric_notes;
                            }
                        }
                    }
                    fabricRadios.forEach(function(radio) {
                        radio.disabled = !!enabled;
                    });
                    if (fabricNotes) {
                        fabricNotes.disabled = !!enabled;
                        fabricNotes.readOnly = !!enabled;
                    }
                }

                function applySupplierSyncStateToBlock(block, enabled) {
                    if (!block) return;
                    var input = block.querySelector('.n88-invite-input');
                    var addBtn = block.querySelector('.n88-invite-add-btn');
                    var allowSystemBox = block.querySelector('.n88-allow-system-invites');
                    var supplierField = input ? input.closest('.n88-field') : null;
                    block.n88SyncSuppliersFromFirst = !!enabled;
                    if (supplierField) supplierField.classList.toggle('n88-sync-locked', !!enabled);
                    if (!isFirstAddItemBlock(block) && enabled) {
                        var firstBlock = getFirstAddItemBlock();
                        if (firstBlock) {
                            var payload = getSupplierSyncPayload(firstBlock);
                            block.n88InvitedSuppliers = payload.invited_suppliers.slice();
                            if (allowSystemBox) {
                                allowSystemBox.checked = !!payload.allow_system_invites;
                                allowSystemBox.disabled = true;
                            }
                            if (typeof block.n88RenderInviteChips === 'function') {
                                block.n88RenderInviteChips();
                            }
                        }
                    } else {
                        if (allowSystemBox) allowSystemBox.disabled = false;
                    }
                    if (input) {
                        input.disabled = !!enabled;
                        input.readOnly = !!enabled;
                    }
                    if (addBtn) addBtn.disabled = !!enabled;
                    block.querySelectorAll('.n88-invite-chip-remove').forEach(function(btn) {
                        btn.disabled = !!enabled;
                    });
                }

                function refreshMultiItemSharedFieldSync() {
                    if (!blocksContainer) return;
                    var firstBlock = getFirstAddItemBlock();
                    var blocks = blocksContainer.querySelectorAll('.n88-add-item-block');
                    blocks.forEach(function(block, index) {
                        var isFirst = !!(firstBlock && block === firstBlock);
                        var deliveryToggle = block.querySelector('.n88-delivery-sync-toggle');
                        var deliveryCheckbox = block.querySelector('.n88-sync-delivery-from-first');
                        var deliveryDateToggle = block.querySelector('.n88-delivery-date-sync-toggle');
                        var deliveryDateCheckbox = block.querySelector('.n88-sync-delivery-date-from-first');
                        var suppliersToggle = block.querySelector('.n88-suppliers-sync-toggle');
                        var suppliersCheckbox = block.querySelector('.n88-sync-suppliers-from-first');
                        var fabricToggle = block.querySelector('.n88-fabric-sync-toggle');
                        var fabricCheckbox = block.querySelector('.n88-sync-fabric-from-first');

                        if (deliveryToggle) {
                            deliveryToggle.classList.toggle('visible', !isFirst);
                            deliveryToggle.hidden = isFirst;
                            deliveryToggle.style.display = isFirst ? 'none' : 'flex';
                        }
                        if (deliveryDateToggle) {
                            deliveryDateToggle.classList.toggle('visible', !isFirst);
                            deliveryDateToggle.hidden = isFirst;
                            deliveryDateToggle.style.display = isFirst ? 'none' : 'flex';
                        }
                        if (suppliersToggle) {
                            suppliersToggle.classList.toggle('visible', !isFirst);
                            suppliersToggle.hidden = isFirst;
                            suppliersToggle.style.display = isFirst ? 'none' : 'flex';
                        }
                        if (fabricToggle) {
                            fabricToggle.classList.toggle('visible', !isFirst);
                            fabricToggle.hidden = isFirst;
                            fabricToggle.style.display = isFirst ? 'none' : 'flex';
                        }

                        if (isFirst) {
                            if (deliveryCheckbox) deliveryCheckbox.checked = false;
                            if (deliveryDateCheckbox) deliveryDateCheckbox.checked = false;
                            if (suppliersCheckbox) suppliersCheckbox.checked = false;
                            if (fabricCheckbox) fabricCheckbox.checked = false;
                            applyDeliverySyncStateToBlock(block, false);
                            applyDeliveryDateSyncStateToBlock(block, false);
                            applySupplierSyncStateToBlock(block, false);
                            applyFabricSyncStateToBlock(block, false);
                        } else {
                            applyDeliverySyncStateToBlock(block, !!(deliveryCheckbox && deliveryCheckbox.checked));
                            applyDeliveryDateSyncStateToBlock(block, !!(deliveryDateCheckbox && deliveryDateCheckbox.checked));
                            applySupplierSyncStateToBlock(block, !!(suppliersCheckbox && suppliersCheckbox.checked));
                            applyFabricSyncStateToBlock(block, !!(fabricCheckbox && fabricCheckbox.checked));
                        }
                    });
                }

                function renderPreviewsForBlock(block, files) {
                    var wrap = block.querySelector('.n88-image-preview-wrap');
                    if (!wrap) return;
                    wrap.innerHTML = '';
                    wrap.classList.toggle('visible', files && files.length > 0);
                    if (!files || files.length === 0) return;
                    var uploadZone = block.querySelector('.n88-upload-zone');
                    var uploadText = block.querySelector('.n88-upload-text, [id$="upload-text"]');
                    if (typeof block.n88PrimaryIndex !== 'number') {
                        block.n88PrimaryIndex = 0;
                    }
                    if (!Array.isArray(block.n88Captions)) {
                        block.n88Captions = [];
                    }
                    for (var i = 0; i < files.length; i++) {
                        (function(idx) {
                            var file = files[idx];
                            var name = (file.name || '').toLowerCase();
                            var isHeic = name.endsWith('.heic') || name.endsWith('.heif');
                            var wrapEl = document.createElement('div');
                            wrapEl.className = 'n88-preview-item';
                            if (!isHeic && file.type && file.type.indexOf('image/') === 0) {
                                var url = URL.createObjectURL(file);
                                var img = document.createElement('img');
                                img.src = url;
                                img.alt = 'Preview ' + (idx + 1);
                                img.onload = function() { URL.revokeObjectURL(url); };
                                wrapEl.appendChild(img);
                            } else {
                                var place = document.createElement('div');
                                place.style.cssText = 'width:80px;height:80px;background:#222;color:#888;font-size:10px;display:flex;align-items:center;justify-content:center;border-radius:4px;';
                                place.textContent = '[img]';
                                wrapEl.appendChild(place);
                            }
                            // Primary selector for this block (only when multiple images)
                            if (files.length > 1) {
                                var primaryBtn = document.createElement('button');
                                primaryBtn.type = 'button';
                                primaryBtn.className = 'n88-preview-primary';
                                primaryBtn.textContent = 'Primary';
                                primaryBtn.onclick = function() {
                                    block.n88PrimaryIndex = idx;
                                    var items = wrap.querySelectorAll('.n88-preview-item');
                                    items.forEach(function(el, index) {
                                        if (index === block.n88PrimaryIndex) {
                                            el.classList.add('n88-primary-selected');
                                        } else {
                                            el.classList.remove('n88-primary-selected');
                                        }
                                    });
                                };
                                wrapEl.appendChild(primaryBtn);
                            }

                            // Remove button
                            var btn = document.createElement('button');
                            btn.type = 'button';
                            btn.className = 'n88-preview-remove';
                            btn.setAttribute('aria-label', 'Remove');
                            btn.textContent = '\u00D7';
                            btn.onclick = function() {
                                files.splice(idx, 1);
                                if (Array.isArray(block.n88Captions) && block.n88Captions.length > idx) {
                                    block.n88Captions.splice(idx, 1);
                                }
                                if (block.n88PrimaryIndex === idx) {
                                    block.n88PrimaryIndex = 0;
                                } else if (block.n88PrimaryIndex > idx) {
                                    block.n88PrimaryIndex--;
                                }
                                renderPreviewsForBlock(block, files);
                                if (uploadText) uploadText.textContent = files.length === 0 ? defaultUploadLabel : (files.length + ' files selected');
                                if (uploadZone) uploadZone.classList.toggle('has-file', files.length > 0);
                            };
                            wrapEl.appendChild(btn);

                            // Caption input per image (Notes)
                            var captionInput = document.createElement('input');
                            captionInput.type = 'text';
                            captionInput.className = 'n88-preview-caption';
                            captionInput.maxLength = 100;
                            captionInput.placeholder = 'Notes (max 100)';
                            captionInput.value = (block.n88Captions[idx] || '').slice(0, 100);
                            captionInput.oninput = function(e) {
                                if (!Array.isArray(block.n88Captions)) {
                                    block.n88Captions = [];
                                }
                                block.n88Captions[idx] = (e.target.value || '').slice(0, 100);
                            };
                            wrapEl.appendChild(captionInput);

                            wrap.appendChild(wrapEl);
                        })(i);
                    }
                    // Ensure a valid primary index for this block
                    if (files.length > 0 && (block.n88PrimaryIndex < 0 || block.n88PrimaryIndex >= files.length)) {
                        block.n88PrimaryIndex = 0;
                    }
                    var items = wrap.querySelectorAll('.n88-preview-item');
                    items.forEach(function(el, index) {
                        if (index === block.n88PrimaryIndex) {
                            el.classList.add('n88-primary-selected');
                        } else {
                            el.classList.remove('n88-primary-selected');
                        }
                    });
                }
                function addAnotherItemBlock() {
                    var first = blocksContainer ? blocksContainer.querySelector('.n88-add-item-block') : null;
                    if (!first) return;
                    var nextIdx = getNextBlockIndex();
                    var clone = first.cloneNode(true);
                    clone.classList.add('n88-item-block-expanded');
                    clone.classList.remove('n88-item-block-collapsed');
                    clone.setAttribute('data-index', nextIdx);
                    var header = clone.querySelector('.n88-item-block-header');
                    if (header) {
