                        var projectId = payloads[0].projectId;
                        var roomId = payloads[0].roomId;
                        var primaryActionBtn = (shouldSubmitRfqAfterCreate && submitRfqDirectBtn) ? submitRfqDirectBtn : submitBtn;
                        
                        submitBtn.disabled = true;
