                                                          (window.n88 && window.n88.ajaxUrl) || 
                                                          (typeof ajaxurl !== 'undefined' ? ajaxurl : '<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>');
                                            var nonce = '';
                                            if (window.n88BoardNonce && window.n88BoardNonce.nonce_submit_rfq) {
                                                nonce = window.n88BoardNonce.nonce_submit_rfq;
                                            } else if (window.n88BoardData && window.n88BoardData.nonce) {
                                                nonce = window.n88BoardData.nonce;
                                            } else if (window.n88 && window.n88.nonce) {
                                                nonce = window.n88.nonce;
                                            } else if (window.n88BoardNonce && window.n88BoardNonce.nonce) {
                                                nonce = window.n88BoardNonce.nonce;
                                            } else {
                                                nonce = '<?php echo esc_js( wp_create_nonce( 'n88_submit_rfq' ) ); ?>';
                                            }
                                            
                                            if (!nonce) {
                                                alert('Security token missing. Please refresh the page and try again.');
                                                return;
                                            }
                                            
                                            rfqBtn.disabled = true;
                                            var originalText = rfqBtn.textContent;
                                            rfqBtn.textContent = isSingle ? '[ Sending Request... ]' : '[ Sending Requests... ]';
                                            
                                            var fd = new FormData();
                                            fd.append('action', 'n88_submit_rfq');
                                            fd.append('items', JSON.stringify(itemsForRfq));
                                            fd.append('invited_suppliers', JSON.stringify(invited));
                                            fd.append('allow_system_invites', allowSystem ? '1' : '0');
                                            fd.append('_ajax_nonce', nonce);
                                            
                                            fetch(ajaxUrl, {
                                                method: 'POST',
                                                body: fd
                                            }).then(function(response) {
                                                return response.json();
                                            }).then(function(data) {
                                                if (data.success) {
                                                    alert((data.data && data.data.message) || 'RFQ submitted successfully!');
                                                    // Close modal and reload board to reflect latest RFQ state
                                                    closeAddItemModal();
                                                    window.location.reload();
                                                } else {
                                                    var msg = (data && data.data && data.data.message) ? data.data.message : 'An error occurred while submitting RFQ.';
                                                    alert(msg);
                                                    rfqBtn.disabled = false;
                                                    rfqBtn.textContent = originalText;
                                                }
                                            }).catch(function(err) {
                                                console.error('Error submitting RFQ from Add Item:', err);
                                                alert('Request failed. Please try again.');
                                                rfqBtn.disabled = false;
                                                rfqBtn.textContent = originalText;
                                            });
                                        } catch (err) {
                                            console.error('Error handling Request Quote Now:', err);
                                        }
                                    };
                                } catch (e) {
                                    console.error('Post-save RFQ overlay error:', e);
                                }
                                <?php else : ?>
                                form.reset();
                                n88ModalSelectedFiles = [];
                                if (uploadZone) { uploadZone.classList.remove('has-file'); if (uploadText) uploadText.textContent = 'Upload sketches, inspiration photos, shop drawings, or material references'; }
                                if (fileInput) fileInput.value = '';
                                if (previewWrap) { previewWrap.innerHTML = ''; previewWrap.classList.remove('visible'); }
                                <?php endif; ?>
                                return;
                            }
                            var p = payloads[idx];
                            fetch(ajaxUrl, { method: 'POST', body: p.formData })
                                .then(function(r) { return r.json(); })
                                .then(function(res) {
                                    if (!res.success) {
                                        submitBtn.disabled = false;
                                        if (submitRfqDirectBtn) submitRfqDirectBtn.disabled = false;
                                        submitBtn.innerHTML = defaultText;
                                        if (submitRfqDirectBtn) submitRfqDirectBtn.innerHTML = defaultDirectText;
                                        resultEl.textContent = 'Error: ' + (res.data && res.data.message ? res.data.message : 'Unknown error');
                                        resultEl.className = 'n88-result error';
                                        updateDirectRfqButtonVisibility();
                                        return;
                                    }
                                    if (res.data && res.data.item_id) {
                                        createdItemIds.push(res.data.item_id);
                                    }
                                    idx++;
                                    submitNext();
                                })
                                .catch(function() {
                                    submitBtn.disabled = false;
                                    if (submitRfqDirectBtn) submitRfqDirectBtn.disabled = false;
                                    submitBtn.innerHTML = defaultText;
                                    if (submitRfqDirectBtn) submitRfqDirectBtn.innerHTML = defaultDirectText;
                                    resultEl.textContent = 'Request failed. Please try again.';
                                    resultEl.className = 'n88-result error';
                                    updateDirectRfqButtonVisibility();
                                });
                        }
                        submitNext();
                    });
                }

                // Reset modal to single block when opening (optional: remove to keep multiple blocks across opens)
                var origOpenAddItemModal = openAddItemModal;
                openAddItemModal = function() {
                    if (blocksContainer) {
                        var blocks = blocksContainer.querySelectorAll('.n88-add-item-block');
                        for (var i = 1; i < blocks.length; i++) blocks[i].remove();
                    }

                    // Auto-select project/room when opened from project or room views
                    try {
                        var url = new URL(window.location.href);
                        var projectIdParam = url.searchParams.get('project_id') || '';
                        var roomIdParam = url.searchParams.get('room_id') || '';
                        var firstBlock = blocksContainer ? blocksContainer.querySelector('.n88-add-item-block') : null;
                        if (firstBlock) {
                            // Project preselect/lock
                            var projSel = firstBlock.querySelector('select[name="project_id"]');
                            if (projSel && projectIdParam && projectIdParam !== '0') {
                                projSel.value = projectIdParam;
                                projSel.disabled = true; // locked when launched from a project board
                                loadRoomsForBlock(firstBlock, projectIdParam);
                            }
                            // Room preselect (room remains editable so designers can change per item)
                            if (roomIdParam && roomIdParam !== '0') {
                                setTimeout(function() {
                                    var roomSelBlock = firstBlock.querySelector('select[name="room_id"]');
                                    if (roomSelBlock) {
                                        roomSelBlock.value = roomIdParam;
                                    }
                                }, 800);
                            }
                        }
                    } catch (e) {
                        // Fail silently if URL parsing fails
                    }

                    origOpenAddItemModal();
                };
            })();
            </script>
            
            <script>
            // Ensure board container expands to fit all items horizontally
            (function() {
                function updateBoardContainerWidth() {
                    var container = document.getElementById('n88-board-canvas-container');
                    var root = document.getElementById('n88-board-demo-root');
                    if (!container || !root) {
                        console.log('Board container or root not found');
                        return;
                    }
                    
                    // Wait for items to render, then calculate max width
                    setTimeout(function() {
                        // Try multiple selectors to find items
                        var items = root.querySelectorAll('[style*="position: absolute"], [style*="position:absolute"]');
                        if (items.length === 0) {
                            // Try finding items by checking all children
                            var allChildren = root.querySelectorAll('*');
                            items = Array.from(allChildren).filter(function(el) {
                                var style = window.getComputedStyle(el);
                                return style.position === 'absolute';
                            });
                        }
                        
                        console.log('Found items for width calculation:', items.length);
                        
                        var maxX = 0;
                        var maxY = 0;
                        
                        items.forEach(function(item) {
                            var style = window.getComputedStyle(item);
                            var left = parseFloat(style.left) || 0;
                            var top = parseFloat(style.top) || 0;
                            var width = parseFloat(style.width) || 0;
                            var height = parseFloat(style.height) || 0;
                            var totalX = left + width;
                            var totalY = top + height;
                            if (totalX > maxX) {
                                maxX = totalX;
                            }
                            if (totalY > maxY) {
                                maxY = totalY;
                            }
                        });
                        
                        // Set minimum width and height to accommodate all items with padding
                        if (maxX > 0) {
                            root.style.minWidth = Math.max(maxX + 100, window.innerWidth) + 'px';
                            console.log('Set root minWidth to:', root.style.minWidth);
                        }
                        if (maxY > 0) {
                            root.style.minHeight = Math.max(maxY + 100, window.innerHeight - 200) + 'px';
                            console.log('Set root minHeight to:', root.style.minHeight);
                        }
                    }, 1500); // Wait 1.5 seconds for React to render items
                }
                
                // Run on load and after a delay to catch React-rendered items
                if (document.readyState === 'loading') {
                    document.addEventListener('DOMContentLoaded', updateBoardContainerWidth);
                } else {
                    updateBoardContainerWidth();
                }
                
                // Also run after React renders (check periodically)
                var checkInterval = setInterval(function() {
                    var root = document.getElementById('n88-board-demo-root');
                    var container = document.getElementById('n88-board-canvas-container');
                    if (root && container) {
                        var hasChildren = root.children.length > 0;
                        var absSel = '[style*="position: absolute"], [style*="position:absolute"], [style*="transform"]';
                        var hasAbsoluteItems = root.querySelectorAll(absSel).length > 0;
                        
                        console.log('Checking board render - children:', root.children.length, 'absolute items:', hasAbsoluteItems);
                        
                        if (hasChildren || hasAbsoluteItems) {
                            updateBoardContainerWidth();
                            clearInterval(checkInterval);
                            
                            // Debug: Log container and root dimensions
                            console.log('Container dimensions:', {
                                width: container.offsetWidth,
                                height: container.offsetHeight,
                                scrollWidth: container.scrollWidth,
                                scrollHeight: container.scrollHeight
                            });
                            console.log('Root dimensions:', {
                                width: root.offsetWidth,
                                height: root.offsetHeight,
                                scrollWidth: root.scrollWidth,
                                scrollHeight: root.scrollHeight
                            });
                        }
                    }
                }, 500);
                
                // Clear interval after 15 seconds
                setTimeout(function() {
                    clearInterval(checkInterval);
                }, 15000);
                
            })();
            </script>
            
