                                } catch (saveError) {
                                    console.error('Error saving item facts after RFQ submission:', saveError);
                                    // Don't block RFQ submission if save fails, just log it
                                }
                                
                                alert(data.data.message || 'RFQ submitted successfully!');
                                setShowRfqForm(false);
