                                setIsSaving(false);
                                return;
                            }
                            
                            // Prepare payload
                            var dimsCm = computedValues.dimsCm;
                            // Process quantity - ensure it's always included if it has a value
                            var qtyValue = null;
                            if (quantity !== '' && quantity !== null && quantity !== undefined) {
                                var parsedQty = parseInt(quantity);
                                if (!isNaN(parsedQty) && parsedQty >= 0) {
                                    qtyValue = parsedQty;
                                }
