                                var parsedQty = parseInt(quantity);
                                if (!isNaN(parsedQty) && parsedQty >= 0) {
                                    qtyValue = parsedQty;
                                }
                            }
                            
                            var payload = {};
                            var notesValue = smartAlternativesNote || '';
                            
                            payload.title = title;
                            payload.category = category;
